import { useEffect, useState } from 'react';
import { useGameStore } from '../store/gameStore';
import { REALMS } from '../types';

export const BreakthroughOverlay = () => {
    const breakthroughMsg = useGameStore(s => s.breakthroughMsg);
    const ackBreakthrough = useGameStore(s => s.ackBreakthrough);
    const realmIdx = useGameStore(s => s.gameState.realm_idx);
    const [isVisible, setIsVisible] = useState(false);

    useEffect(() => {
        if (breakthroughMsg && breakthroughMsg.includes('突破成功')) {
            setIsVisible(true);
        }
    }, [breakthroughMsg]);

    const handleClose = () => {
        setIsVisible(false);
        setTimeout(() => {
            ackBreakthrough();
        }, 300); // Wait for fade out
    };

    if (!isVisible && !breakthroughMsg) return null;

    // Use current realm name. Note: When breakthrough happens, realm_idx is already updated.
    // So current `realmIdx` is the NEW realm.
    // We can show "晋升" -> REALMS[realmIdx]
    const realmName = REALMS[realmIdx];

    return (
        <div
            className={`fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm transition-opacity duration-500 ${isVisible ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
            onClick={handleClose}
        >
            <div
                className={`relative max-w-lg w-full p-8 text-center transform transition-all duration-700 ${isVisible ? 'scale-100 translate-y-0' : 'scale-90 translate-y-10'}`}
                onClick={e => e.stopPropagation()}
            >
                {/* Background Effects */}
                <div className="absolute inset-0 bg-gradient-to-b from-emerald-900/40 to-slate-900/80 rounded-2xl border border-emerald-500/30 shadow-[0_0_50px_rgba(16,185,129,0.2)]"></div>

                {/* Decorative Elements */}
                <div className="absolute -top-6 -left-6 w-12 h-12 border-t-2 border-l-2 border-emerald-500/50"></div>
                <div className="absolute -bottom-6 -right-6 w-12 h-12 border-b-2 border-r-2 border-emerald-500/50"></div>

                {/* Content */}
                <div className="relative z-10">
                    <h2 className="text-4xl font-serif font-bold text-transparent bg-clip-text bg-gradient-to-r from-emerald-200 via-white to-emerald-200 mb-6 drop-shadow-lg tracking-widest animate-pulse-slow">
                        突破成功
                    </h2>

                    <div className="py-8">
                        <div className="text-xl text-slate-400 font-serif mb-2">晋升为</div>
                        <div className="text-5xl font-serif font-bold text-emerald-400 drop-shadow-[0_0_15px_rgba(52,211,153,0.6)] animate-float">
                            {realmName}
                        </div>
                    </div>

                    <p className="text-sm text-slate-300 font-mono bg-black/40 py-2 px-4 rounded inline-block border border-slate-700/50">
                        {breakthroughMsg}
                    </p>

                    <div className="mt-8">
                        <button
                            onClick={handleClose}
                            className="px-8 py-3 bg-emerald-600/20 hover:bg-emerald-600/40 border border-emerald-500/50 text-emerald-100 font-serif rounded-lg transition-all hover:scale-105 active:scale-95"
                        >
                            巩固境界
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useEffect, useState } from 'react';
import { useGameStore } from '../store/gameStore';
import { motion, AnimatePresence } from 'framer-motion';

export const CombatOverlay = () => {
    const { gameState, engine } = useGameStore();
    const combatState = gameState.minigame?.combat; // Assume we'll add this to state

    // Local state for animation effects
    const [shake, setShake] = useState(false);
    const [damageFloater, setDamageFloater] = useState<{ id: number, val: number, isPlayer: boolean }[]>([]);

    if (!combatState || !combatState.isActive) return null;

    const { player, enemy, logs } = combatState;

    // Effects when HP changes (simplified detection)
    // In a real app we'd listen to events or compare props.

    const pPercent = Math.max(0, (player.currentHp / player.maxHp) * 100);
    const ePercent = Math.max(0, (enemy.currentHp / enemy.maxHp) * 100);

    return (
        <div className="absolute inset-0 z-50 bg-black/80 flex flex-col items-center justify-center p-4">
            {/* 战斗场景容器 */}
            <div className="w-full max-w-4xl aspect-video bg-slate-900 border border-slate-700 rounded-lg shadow-2xl relative overflow-hidden flex flex-col">

                {/* 背景特效 (Background FX) */}
                <div className="absolute inset-0 opacity-20 bg-[url('https://images.unsplash.com/photo-1518531933037-91b2f5f229cc?q=80&w=1000')] bg-cover bg-center mix-blend-overlay pointer-events-none"></div>

                {/* 顶部：双方血条 */}
                <div className="relative z-10 w-full p-8 flex justify-between items-start">

                    {/* 玩家状态 */}
                    <div className="w-1/3 flex flex-col items-start gap-2">
                        <div className="flex items-center gap-3">
                            <div className="w-12 h-12 rounded-full bg-slate-800 border-2 border-emerald-500 overflow-hidden">
                                {/* Avatar placeholder or use SpiritAvatar */}
                                <div className="w-full h-full bg-emerald-900/50 flex items-center justify-center text-emerald-200 font-serif font-bold">我</div>
                            </div>
                            <div>
                                <div className="text-lg font-bold text-slate-100 font-serif tracking-widest">{gameState.name}</div>
                                <div className="text-xs text-emerald-500 font-mono">等级 {Math.floor(gameState.realm_idx)}</div>
                            </div>
                        </div>
                        {/* HP Bar */}
                        <div className="w-full h-4 bg-slate-800 rounded-full border border-slate-700 overflow-hidden relative">
                            <motion.div
                                className="h-full bg-gradient-to-r from-emerald-600 to-emerald-400"
                                initial={{ width: '100%' }}
                                animate={{ width: `${pPercent}%` }}
                                transition={{ type: "spring", stiffness: 100 }}
                            />
                            <div className="absolute inset-0 flex items-center justify-center text-[10px] font-mono font-bold text-white drop-shadow-md">
                                {player.currentHp} / {player.maxHp}
                            </div>
                        </div>
                    </div>

                    {/* VS Icon */}
                    <div className="text-4xl font-black text-red-600/50 pt-4 italic font-serif">VS</div>

                    {/* 敌人状态 */}
                    <div className="w-1/3 flex flex-col items-end gap-2">
                        <div className="flex items-center gap-3 flex-row-reverse">
                            <div className="w-12 h-12 rounded-full bg-slate-800 border-2 border-red-500 overflow-hidden">
                                <div className="w-full h-full bg-red-900/50 flex items-center justify-center text-red-200 font-serif font-bold">敌</div>
                            </div>
                            <div className="text-right">
                                <div className="text-lg font-bold text-slate-100 font-serif tracking-widest">{enemy.name}</div>
                                <div className="text-xs text-red-500 font-mono">妖兽</div>
                            </div>
                        </div>
                        {/* HP Bar */}
                        <div className="w-full h-4 bg-slate-800 rounded-full border border-slate-700 overflow-hidden relative">
                            <motion.div
                                className="h-full bg-gradient-to-l from-red-600 to-red-400"
                                initial={{ width: '100%' }}
                                animate={{ width: `${ePercent}%` }}
                                transition={{ type: "spring", stiffness: 100 }}
                            />
                            <div className="absolute inset-0 flex items-center justify-center text-[10px] font-mono font-bold text-white drop-shadow-md">
                                {enemy.currentHp} / {enemy.maxHp}
                            </div>
                        </div>
                    </div>
                </div>

                {/* 中间：战斗动画区 (简单文字冒泡 或 粒子) */}
                <div className="flex-1 relative flex items-center justify-center">
                    {/* 这里可以放技能特效 */}
                    <div className="text-slate-700/30 text-6xl font-serif font-bold select-none">
                        激战中...
                    </div>
                </div>

                {/* 底部：战斗日志 */}
                <div className="h-48 w-full bg-black/60 backdrop-blur-md border-t border-slate-700 p-4 overflow-y-auto custom-scrollbar">
                    <div className="flex flex-col gap-1">
                        {logs.slice(-6).map((log, i) => (
                            <motion.div
                                key={i}
                                initial={{ opacity: 0, x: -20 }}
                                animate={{ opacity: 1, x: 0 }}
                                className="text-sm font-mono text-slate-300"
                            >
                                <span className="text-slate-500">[{log.turn}]</span> {log.message}
                            </motion.div>
                        ))}
                    </div>
                </div>

                {/* 逃跑按钮 (Optional) */}
                <div className="absolute bottom-4 right-4">
                    <button
                        onClick={() => engine.endCombat(false)} // Assume engine method
                        className="px-4 py-2 bg-slate-800 border border-slate-600 rounded text-slate-400 hover:text-white hover:bg-slate-700 text-xs"
                    >
                        撤退
                    </button>
                </div>
            </div>
        </div>
    );
};

import { useState } from 'react';
import { useGameStore } from '../store/gameStore';
import { MAIN_QUESTS } from '../data/missions';
import type { Mission } from '../types/missionTypes';

interface MissionLogModalProps {
    onClose: () => void;
}

export const MissionLogModal = ({ onClose }: MissionLogModalProps) => {
    const { gameState } = useGameStore();
    const [selectedTab, setSelectedTab] = useState<'ACTIVE' | 'COMPLETED'>('ACTIVE');
    const [selectedMissionId, setSelectedMissionId] = useState<string | null>(null);

    const activeMissions = gameState.missions?.active || [];
    const completedMissionIds = gameState.missions?.completed || [];

    // Helper to get mission definition
    const getMissionDef = (id: string) => MAIN_QUESTS.find(m => m.id === id);

    // Filtered lists
    const activeList = activeMissions.map(m => ({ ...m, def: getMissionDef(m.id) })).filter(m => m.def);
    const completedList = completedMissionIds.map(id => ({ id, def: getMissionDef(id) })).filter(m => m.def);

    // Current selection
    const currentList = selectedTab === 'ACTIVE' ? activeList : completedList;
    const selectedMission = currentList.find(m => m.id === selectedMissionId) || currentList[0];

    return (
        <div className="fixed inset-0 z-[100] bg-black/80 flex items-center justify-center p-4 backdrop-blur-sm">
            <div className="w-full max-w-4xl h-[600px] bg-slate-900 border border-slate-700 rounded-lg shadow-2xl flex flex-col overflow-hidden animate-fade-in-up">

                {/* Header */}
                <div className="h-14 bg-slate-950/50 border-b border-slate-800 flex items-center justify-between px-6 shrink-0">
                    <h2 className="text-lg font-serif font-bold text-slate-200 tracking-widest flex items-center gap-2">
                        <span className="text-amber-500">❖</span> 任务日志
                    </h2>
                    <button
                        onClick={onClose}
                        className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-slate-800 text-slate-500 hover:text-slate-300 transition-colors"
                    >
                        ✕
                    </button>
                </div>

                <div className="flex-1 flex min-h-0">
                    {/* Left Sidebar: List */}
                    <div className="w-64 bg-slate-950/30 border-r border-slate-800 flex flex-col">
                        {/* Tabs */}
                        <div className="flex border-b border-slate-800">
                            <button
                                onClick={() => setSelectedTab('ACTIVE')}
                                className={`flex-1 py-3 text-sm font-serif transition-colors ${selectedTab === 'ACTIVE' ? 'bg-slate-800/50 text-amber-400 border-b-2 border-amber-500' : 'text-slate-500 hover:text-slate-300'}`}
                            >
                                进行中 ({activeList.length})
                            </button>
                            <button
                                onClick={() => setSelectedTab('COMPLETED')}
                                className={`flex-1 py-3 text-sm font-serif transition-colors ${selectedTab === 'COMPLETED' ? 'bg-slate-800/50 text-emerald-400 border-b-2 border-emerald-500' : 'text-slate-500 hover:text-slate-300'}`}
                            >
                                已完成 ({completedList.length})
                            </button>
                        </div>

                        {/* Mission List */}
                        <div className="flex-1 overflow-y-auto custom-scrollbar p-2 space-y-1">
                            {currentList.length === 0 ? (
                                <div className="p-4 text-center text-xs text-slate-600 font-mono">
                                    暂无{selectedTab === 'ACTIVE' ? '进行中' : '已完成'}任务
                                </div>
                            ) : (
                                currentList.map((item) => (
                                    <button
                                        key={item.id}
                                        onClick={() => setSelectedMissionId(item.id)}
                                        className={`w-full text-left px-3 py-2 rounded border transition-all ${(selectedMission?.id === item.id)
                                            ? 'bg-slate-800 border-slate-600 text-slate-200 shadow-sm'
                                            : 'bg-transparent border-transparent text-slate-500 hover:bg-slate-800/30 hover:text-slate-300'
                                            }`}
                                    >
                                        <div className="text-sm font-bold truncate">{item.def?.title || item.id}</div>
                                        <div className="text-[10px] opacity-60 truncate">{item.def?.type === 'MAIN' ? '主线' : '支线'}</div>
                                    </button>
                                ))
                            )}
                        </div>
                    </div>

                    {/* Right Content: Details */}
                    <div className="flex-1 bg-slate-900/50 p-6 overflow-y-auto custom-scrollbar relative">
                        {selectedMission ? (
                            <div className="max-w-2xl mx-auto space-y-6">
                                {/* Title & Badge */}
                                <div className="flex items-start justify-between border-b border-slate-700/50 pb-4">
                                    <div>
                                        <h1 className="text-2xl font-serif font-bold text-slate-100 mb-2">{selectedMission.def?.title}</h1>
                                        <div className="flex items-center gap-2">
                                            <span className={`text-xs px-2 py-0.5 rounded border ${selectedTab === 'ACTIVE'
                                                ? 'bg-amber-950/30 border-amber-800/50 text-amber-500'
                                                : 'bg-emerald-950/30 border-emerald-800/50 text-emerald-500'
                                                }`}>
                                                {selectedTab === 'ACTIVE' ? '进行中' : '已完成'}
                                            </span>
                                            <span className="text-xs text-slate-500 font-mono">编号: {selectedMission.id}</span>
                                        </div>
                                    </div>
                                    {selectedTab === 'COMPLETED' && (
                                        <div className="w-16 h-16 rounded-full border-2 border-emerald-500/30 text-emerald-500/30 flex items-center justify-center font-serif font-bold text-xl rotate-12 select-none">
                                            完 成
                                        </div>
                                    )}
                                </div>

                                {/* Description */}
                                <div className="bg-slate-950/30 rounded-lg p-4 border border-slate-800/50">
                                    <p className="text-slate-300 leading-relaxed text-sm">
                                        {selectedMission.def?.description}
                                    </p>
                                </div>

                                {/* Objectives */}
                                <div>
                                    <h3 className="text-sm font-mono text-slate-500 uppercase tracking-widest mb-3 border-l-2 border-slate-700 pl-2">任务目标</h3>
                                    <div className="space-y-2">
                                        {selectedMission.def?.objectives.map((obj, i) => {
                                            // Get progress if active (objectives is Map<string, number>)
                                            const currentCount = ('objectives' in selectedMission && (selectedMission as any).objectives)
                                                ? ((selectedMission as any).objectives[obj.id] || 0)
                                                : (selectedTab === 'COMPLETED' ? obj.requiredCount : 0);

                                            const current = currentCount;
                                            const needed = obj.requiredCount;
                                            const isDone = current >= needed;

                                            return (
                                                <div key={obj.id} className="flex items-center justify-between p-3 bg-slate-800/20 rounded border border-slate-800/50">
                                                    <div className="flex items-center gap-3">
                                                        <div className={`w-4 h-4 rounded-full border flex items-center justify-center ${isDone ? 'bg-emerald-500 border-emerald-500' : 'border-slate-600'}`}>
                                                            {isDone && <svg className="w-2.5 h-2.5 text-black" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="3"><path d="M5 13l4 4L19 7" /></svg>}
                                                        </div>
                                                        <span className={`text-sm ${isDone ? 'text-slate-400 line-through' : 'text-slate-200'}`}>
                                                            {obj.description}
                                                        </span>
                                                    </div>
                                                    <div className="text-xs font-mono text-slate-500">
                                                        {current} / {needed}
                                                    </div>
                                                </div>
                                            );
                                        })}
                                    </div>
                                </div>

                                {/* Rewards */}
                                {selectedMission.def?.rewards && (
                                    <div>
                                        <h3 className="text-sm font-mono text-slate-500 uppercase tracking-widest mb-3 border-l-2 border-slate-700 pl-2">任务奖励</h3>
                                        <div className="flex items-center gap-3 p-4 bg-amber-950/10 border border-amber-900/20 rounded-lg text-amber-200/80 text-sm">
                                            <span className="text-lg">🎁</span>
                                            <span>{selectedMission.def.rewards.text}</span>
                                        </div>
                                    </div>
                                )}

                            </div>
                        ) : (
                            <div className="flex flex-col items-center justify-center h-full text-slate-600">
                                <span className="text-4xl mb-4 opacity-50">📜</span>
                                <p>请选择一个任务查看详情</p>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

import { useMemo } from 'react';

interface SpiritAvatarProps {
    seed: string;
    realm: string;
    attributes: Record<string, number>;
    className?: string;
}

export const SpiritAvatar = ({ seed, realm, attributes, className = "" }: SpiritAvatarProps) => {
    // Generate deterministic colors/shapes based on seed and attributes
    const { primaryColor, secondaryColor, shapeConfig } = useMemo(() => {
        let hash = 0;
        for (let i = 0; i < seed.length; i++) {
            hash = seed.charCodeAt(i) + ((hash << 5) - hash);
        }

        const colors = [
            '#10b981', // Emerald
            '#0ea5e9', // Sky
            '#8b5cf6', // Violet
            '#f59e0b', // Amber
            '#ef4444', // Red
            '#6366f1', // Indigo
        ];

        const pIndex = Math.abs(hash) % colors.length;
        const sIndex = Math.abs(hash >> 3) % colors.length;

        // Shape complexity based on attributes (e.g. Total Stats)
        const totalStats = Object.values(attributes).reduce((a, b) => a + b, 0);
        const complexity = Math.min(10, Math.floor(totalStats / 50)) + 3;

        return {
            primaryColor: colors[pIndex],
            secondaryColor: colors[sIndex !== pIndex ? sIndex : (sIndex + 1) % colors.length],
            shapeConfig: {
                points: complexity,
                rotation: hash % 360
            }
        };
    }, [seed, attributes]);

    return (
        <div className={`relative w-full h-full flex items-center justify-center overflow-hidden ${className}`}>
            <svg viewBox="0 0 100 100" className="w-full h-full animate-pulse-slow">
                <defs>
                    <radialGradient id={`grad-${seed}`} cx="50%" cy="50%" r="50%" fx="50%" fy="50%">
                        <stop offset="0%" stopColor={primaryColor} stopOpacity="0.8" />
                        <stop offset="100%" stopColor={secondaryColor} stopOpacity="0" />
                    </radialGradient>
                    <filter id="glow">
                        <feGaussianBlur stdDeviation="2.5" result="coloredBlur" />
                        <feMerge>
                            <feMergeNode in="coloredBlur" />
                            <feMergeNode in="SourceGraphic" />
                        </feMerge>
                    </filter>
                </defs>

                {/* Core Spirit Orb */}
                <circle cx="50" cy="50" r="30" fill={`url(#grad-${seed})`} filter="url(#glow)" className="animate-float" />

                {/* Orbiting Particles based on Realm? */}
                <circle cx="50" cy="20" r="2" fill={secondaryColor} className="animate-orbit-1" />
                <circle cx="50" cy="80" r="3" fill={primaryColor} className="animate-orbit-2" />
            </svg>

            {/* Realm Text Overlay (Optional) */}
            {/* <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                <span className="text-[10px] font-mono text-white/50">{realm}</span>
            </div> */}
        </div>
    );
};

import React from 'react';
import type { Region, Location, LocationType } from '../../types/worldTypes';
import { motion } from 'framer-motion';

interface MapNodeProps {
    data: Region | Location;
    isRegionCenter?: boolean;
    isActive?: boolean;
    isLocked?: boolean;
    onClick?: (id: string) => void;
}

const TYPE_COLORS: Record<string, string> = {
    'CITY': '#4ade80',      // Green
    'SECT_HQ': '#f87171',   // Red
    'SECRET_REALM': '#a78bfa', // Purple
    'WILDERNESS': '#9ca3af', // Gray
    'MINE': '#fbbf24',      // Amber
    'HERB_GARDEN': '#34d399', // Emerald
    'SPIRIT_VEIN': '#60a5fa', // Blue
    'RUINS': '#fb923c',     // Orange
    'MARKET': '#fcd34d',    // Yellow
    'REGION_CENTER': '#e2e8f0', // White
};

export const MapNode: React.FC<MapNodeProps> = ({ data, isRegionCenter, isActive, isLocked, onClick }) => {
    const { x, y } = data.coord;
    const type = isRegionCenter ? 'REGION_CENTER' : (data as Location).type;
    const color = TYPE_COLORS[type] || '#ffffff';

    // Size based on importance
    const size = isRegionCenter ? 24 : 12;
    const glowSize = isActive ? size * 2.5 : size * 1.5;

    return (
        <div
            className="absolute transform -translate-x-1/2 -translate-y-1/2 cursor-pointer group"
            style={{ left: `${x}%`, top: `${y}%` }}
            onClick={() => onClick && onClick(data.id)}
        >
            {/* Glow Effect */}
            <motion.div
                className="absolute rounded-full opacity-30 select-none pointer-events-none"
                style={{
                    backgroundColor: color,
                    width: glowSize,
                    height: glowSize,
                    left: '50%',
                    top: '50%',
                    x: '-50%',
                    y: '-50%'
                }}
                animate={{
                    scale: [1, 1.2, 1],
                    opacity: [0.3, 0.5, 0.3]
                }}
                transition={{
                    duration: 3,
                    repeat: Infinity,
                    ease: "easeInOut"
                }}
            />

            {/* Core Node */}
            <div
                className={`relative rounded-full border-2 transition-colors duration-300 ${isActive ? 'border-white' : 'border-transparent'}`}
                style={{
                    width: size,
                    height: size,
                    backgroundColor: isLocked ? '#333' : color,
                    borderColor: isActive ? '#fff' : (isRegionCenter ? 'rgba(255,255,255,0.5)' : 'transparent')
                }}
            >
                {/* Active Indicator Ring */}
                {isActive && (
                    <motion.div
                        className="absolute -inset-1 border border-white rounded-full"
                        animate={{ scale: [1, 1.5], opacity: [1, 0] }}
                        transition={{ duration: 1.5, repeat: Infinity }}
                    />
                )}
            </div>

            {/* Tooltip on Hover */}
            <div className="absolute top-full left-1/2 transform -translate-x-1/2 mt-2 px-3 py-1 bg-gray-900/90 text-xs text-white rounded whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-50 border border-gray-700">
                <div className="font-bold text-amber-500">{data.name}</div>
                <div className="text-gray-400 scale-90 origin-top">{isRegionCenter ? (data as Region).terrain : (data as Location).type}</div>
            </div>
        </div>
    );
};

import React from 'react';
import { CONDITION_TYPES, CONDITION_OPS } from '../types';
import type { Condition, ConditionType, ConditionOp } from '../types';

interface ConditionBuilderProps {
    conditions: Condition[];
    onChange: (conditions: Condition[]) => void;
}

export const ConditionBuilder: React.FC<ConditionBuilderProps> = ({ conditions = [], onChange }) => {

    const handleAdd = () => {
        // Use string literals or the first item from constants
        onChange([...conditions, { type: 'STAT', target: 'STR', op: 'GTE', value: 10 }]);
    };

    const handleRemove = (index: number) => {
        const next = [...conditions];
        next.splice(index, 1);
        onChange(next);
    };

    const handleChange = (index: number, key: keyof Condition, value: any) => {
        const next = [...conditions];
        next[index] = { ...next[index], [key]: value };
        onChange(next);
    };

    return (
        <div className="space-y-2 p-2 bg-slate-800/50 rounded border border-slate-700">
            <div className="flex items-center justify-between">
                <h4 className="text-xs font-mono text-slate-400">CONDITIONS ({conditions.length})</h4>
                <button
                    onClick={handleAdd}
                    className="text-xs px-2 py-0.5 bg-emerald-700 text-emerald-100 rounded hover:bg-emerald-600"
                >
                    + Add
                </button>
            </div>

            {conditions.length === 0 && (
                <div className="text-xs text-slate-600 italic text-center py-2">No conditions</div>
            )}

            {conditions.map((cond, idx) => (
                <div key={idx} className="flex flex-wrap gap-2 items-center bg-slate-900/50 p-2 rounded border border-slate-800">
                    {/* Type */}
                    <select
                        className="bg-slate-800 text-xs text-slate-300 border border-slate-700 rounded px-1 py-1 w-24"
                        value={cond.type}
                        onChange={e => handleChange(idx, 'type', e.target.value)}
                    >
                        {CONDITION_TYPES.map(t => (
                            <option key={t} value={t}>{t}</option>
                        ))}
                    </select>

                    {/* Target */}
                    <input
                        className="bg-slate-800 text-xs text-slate-300 border border-slate-700 rounded px-2 py-1 flex-1 min-w-[80px]"
                        value={cond.target}
                        onChange={e => handleChange(idx, 'target', e.target.value)}
                        placeholder="Target (e.g. STR)"
                    />

                    {/* Op */}
                    <select
                        className="bg-slate-800 text-xs text-slate-300 border border-slate-700 rounded px-1 py-1 w-16"
                        value={cond.op}
                        onChange={e => handleChange(idx, 'op', e.target.value)}
                    >
                        {CONDITION_OPS.map(op => (
                            <option key={op} value={op}>{op}</option>
                        ))}
                    </select>

                    {/* Value */}
                    <input
                        className="bg-slate-800 text-xs text-slate-300 border border-slate-700 rounded px-2 py-1 w-20"
                        value={String(cond.value)}
                        onChange={e => {
                            const val = e.target.value;
                            // Basic number parsing if it looks like a number
                            const num = Number(val);
                            handleChange(idx, 'value', isNaN(num) ? val : num);
                        }}
                        placeholder="Value"
                    />

                    {/* Delete */}
                    <button
                        onClick={() => handleRemove(idx)}
                        className="text-slate-500 hover:text-red-400 px-1"
                    >
                        ×
                    </button>
                </div>
            ))}
        </div>
    );
};

