import React, { useState, useEffect } from 'react';
import ReactJson from 'react-json-view';
import { useGameStore } from '../store/gameStore';
import { ConditionBuilder } from './ConditionBuilder';
import type { GameEvent, Condition } from '../types';

export const EventEditor: React.FC = () => {
    const { engine } = useGameStore();
    const [selectedEventId, setSelectedEventId] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState('');

    // We maintain a local copy of the event being edited to trigger re-renders
    const [editedEvent, setEditedEvent] = useState<GameEvent | null>(null);

    const events = engine.events;
    const filteredEvents = events.filter(e =>
        e.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
        (e.title && e.title.includes(searchTerm))
    );

    // Sync editedEvent when selection changes
    useEffect(() => {
        if (selectedEventId) {
            const ev = events.find(e => e.id === selectedEventId);
            setEditedEvent(ev ? { ...ev } : null);
        } else {
            setEditedEvent(null);
        }
    }, [selectedEventId, events]);

    const handleSave = () => {
        if (!editedEvent) return;
        const idx = events.findIndex(e => e.id === editedEvent.id);
        if (idx >= 0) {
            events[idx] = editedEvent;
            // Force engine update if needed?
            // Engine usually reads events reference.
            alert('Event saved to memory (Runtime only)');
        }
    };

    const handleConditionChange = (newConditions: Condition[]) => {
        if (!editedEvent) return;
        setEditedEvent({ ...editedEvent, conditions: newConditions });
    };

    return (
        <div className="flex h-full gap-4 text-slate-300">
            {/* List */}
            <div className="w-1/3 flex flex-col gap-2 h-full">
                <input
                    type="text"
                    placeholder="Search events..."
                    className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 text-sm focus:border-emerald-500 outline-none"
                    value={searchTerm}
                    onChange={e => setSearchTerm(e.target.value)}
                />
                <div className="flex-1 overflow-y-auto bg-slate-900 border border-slate-700 rounded-lg p-2 space-y-1 custom-scrollbar">
                    {filteredEvents.map(e => (
                        <button
                            key={e.id}
                            onClick={() => setSelectedEventId(e.id)}
                            className={`w-full text-left p-2 rounded text-sm hover:bg-slate-800 transition-colors ${selectedEventId === e.id ? 'bg-emerald-900/50 border border-emerald-500/50' : ''}`}
                        >
                            <div className="font-bold text-slate-200">{e.title || 'Untitled'}</div>
                            <div className="text-xs text-slate-500 font-mono truncate">{e.id}</div>
                        </button>
                    ))}
                </div>
            </div>

            {/* Detail */}
            <div className="flex-1 bg-slate-900 border border-slate-700 rounded-lg h-full overflow-hidden flex flex-col">
                {editedEvent ? (
                    <div className="flex-1 overflow-y-auto custom-scrollbar p-4 space-y-6">
                        {/* Header Actions */}
                        <div className="flex justify-between items-center mb-4">
                            <h3 className="text-lg font-serif font-bold text-emerald-400">{editedEvent.title}</h3>
                            <button
                                onClick={handleSave}
                                className="px-3 py-1 bg-emerald-700 hover:bg-emerald-600 text-white rounded text-sm"
                            >
                                Save Changes
                            </button>
                        </div>

                        {/* Basic Info */}
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="block text-xs font-mono text-slate-500 mb-1">ID</label>
                                <input
                                    className="w-full bg-slate-800 border border-slate-700 rounded px-2 py-1 text-sm text-slate-300"
                                    value={editedEvent.id}
                                    readOnly
                                />
                            </div>
                            <div>
                                <label className="block text-xs font-mono text-slate-500 mb-1">Title</label>
                                <input
                                    className="w-full bg-slate-800 border border-slate-700 rounded px-2 py-1 text-sm text-slate-300 focus:border-emerald-500 outline-none"
                                    value={editedEvent.title || ''}
                                    onChange={e => setEditedEvent({ ...editedEvent, title: e.target.value })}
                                />
                            </div>
                        </div>

                        {/* Content */}
                        <div>
                            <label className="block text-xs font-mono text-slate-500 mb-1">Content</label>
                            <textarea
                                className="w-full bg-slate-800 border border-slate-700 rounded px-2 py-1 text-sm text-slate-300 h-24 focus:border-emerald-500 outline-none"
                                value={editedEvent.content || ''}
                                onChange={e => setEditedEvent({ ...editedEvent, content: e.target.value })}
                            />
                        </div>

                        {/* Conditions Builder */}
                        <div>
                            <label className="block text-xs font-mono text-slate-500 mb-1">Conditions</label>
                            <ConditionBuilder
                                conditions={editedEvent.conditions || []}
                                onChange={handleConditionChange}
                            />
                        </div>

                        {/* Raw JSON fallback */}
                        <div>
                            <label className="block text-xs font-mono text-slate-500 mb-1">Raw JSON Data</label>
                            <div className="bg-slate-950 p-2 rounded border border-slate-800">
                                <ReactJson
                                    src={editedEvent}
                                    theme="monokai"
                                    collapsed={1}
                                    onEdit={edit => setEditedEvent(edit.updated_src as GameEvent)}
                                    onAdd={edit => setEditedEvent(edit.updated_src as GameEvent)}
                                    onDelete={edit => setEditedEvent(edit.updated_src as GameEvent)}
                                    style={{ backgroundColor: 'transparent', fontSize: '12px' }}
                                />
                            </div>
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 flex items-center justify-center text-slate-600 italic">
                        Select an event to edit
                    </div>
                )}
            </div>
        </div>
    );
};

