import type { PlayerState, GameEvent, Talent, BattleStats, Effect, EventChoice, FortuneBuff } from '../types';
import { REALMS } from '../types';
import { generateNPC, deriveBattleStats, generateName } from '../utils/DataUtils';
import { ConditionMatcher } from '../utils/ConditionMatcher';
import type { ModuleConfig } from '../types/meta';
import { GAME_RULES, NPC_DESCRIPTIONS, TEXT_CONSTANTS, INITIAL_STATE, BATTLE_STATS_DEFAULTS } from '../data/rules';
import { determineFate } from '../modules/xianxia/data/fateData';
import { WorldGenerator } from './WorldGenerator';
import type { Region, Location } from '../types/worldTypes';
import { ITEMS, LOOT_TABLES } from '../data/items';
import { MAIN_QUESTS } from '../data/missions';
import type { Mission, MissionObjective, GenericMissionState } from '../types/missionTypes';

export class GameEngine {
    state: PlayerState;
    events: GameEvent[];
    moduleConfig: ModuleConfig;

    talentsDB: Talent[];

    constructor(config: ModuleConfig, events: GameEvent[], talents: Talent[], initialState?: Partial<PlayerState>) {
        this.moduleConfig = config;
        this.events = events;
        this.talentsDB = talents;
        this.state = { ...this.getInitialState(), ...initialState } as PlayerState;
    }

    getInitialState(): PlayerState {
        // Initialize attributes from Module Config
        const attributes: Record<string, number> = {};
        this.moduleConfig.stats.forEach(s => {
            attributes[s.id] = s.base;
        });

        const initialBattleStats: BattleStats = {
            MAX_HP: attributes.HP || 100,
            MAX_MP: attributes.MP || 0,
            ...BATTLE_STATS_DEFAULTS,
            MOVE_SPEED: 20 // Default fallback
        };

        return {
            name: TEXT_CONSTANTS.DEFAULT_NAME,
            age: 0,
            months: 0,
            day: 1,
            realm_idx: 0,
            gender: Math.random() > 0.5 ? 'Male' : 'Female',
            race: 'HUMAN',
            attributes: attributes,
            battleStats: initialBattleStats,

            talents: [],
            flags: [],
            relationships: [],
            partners: [],
            pets: [],
            home: {
                level: INITIAL_STATE.HOME_LEVEL,
                name: INITIAL_STATE.HOME_NAME,
                modules: [],
                resources: {} // Use generic resources map
            },
            professions: {}, // Generic professions map
            inventory: [],
            triggeredEvents: [],
            history: [],
            alive: true,
            background: 'FARMER', // Default

            // ... (keep existing)
            // World Context
            world: new WorldGenerator({ seed: 0 }, { silent: true }).generate(),

            // [NEW] Personality & Acquired Traits
            personality: {
                // Core Values (-100 to 100)
                'JUSTICE': 0, // Pos: Justice, Neg: Evil
                'COURAGE': 0, // Pos: Brave, Neg: Timid
                'AMBITION': 0 // Pos: Ambitious, Neg: Content
            },
            acquiredTraits: [],

            // [NEW] 世界定位
            location: '',  // 由世界生成后设定
            sect: null,    // 初始为散修

            // [NEW] 命格与气运
            fate: [],
            fortuneBuffs: [],

            // [NEW] Mission System Initialization
            missions: {
                active: [],
                completed: [],
                history: {}
            }
        };
    }

    recalculateStats() {
        this.state.battleStats = deriveBattleStats(this.state.attributes, this.state.realm_idx);
    }

    getLifespan(): number {
        const base = GAME_RULES.BASE_LIFESPAN;
        const bonuses = GAME_RULES.LIFESPAN_BONUSES;
        return base + (bonuses[this.state.realm_idx] || 0);
    }

    // --- Standardization V2 ---

    triggerTalents(trigger: import('../types').TriggerType) {
        this.state.talents.forEach(talent => {
            if (!talent.modifiers) return;

            talent.modifiers.forEach(mod => {
                if (mod.trigger !== trigger) return;

                // Unified Condition Check
                const conditions = mod.conditions || [];
                if (!ConditionMatcher.checkConditions(this.state, conditions)) return;

                // Probability Check
                if (mod.probability !== undefined && Math.random() > mod.probability) return;

                // Apply Effects (Standardized)
                if (mod.stats) {
                    for (const [k, v] of Object.entries(mod.stats)) {
                        if (v !== undefined) {
                            this.state.attributes[k] = (this.state.attributes[k] || 0) + v;
                        }
                    }
                }

                if (mod.battle) {
                    for (const [k, v] of Object.entries(mod.battle)) {
                        if (this.state.battleStats[k] !== undefined && v !== undefined) {
                            this.state.battleStats[k] += v;
                        }
                    }
                }

                if (mod.resource) {
                    for (const [k, v] of Object.entries(mod.resource)) {
                        if (v === undefined) continue;
                        if (k === 'SPIRIT_STONES') {
                            this.state.home.resources.spirit_stones = (this.state.home.resources.spirit_stones || 0) + v;
                        } else {
                            this.state.home.resources[k] = (this.state.home.resources[k] || 0) + v;
                        }
                    }
                }
            });
        });

        // Recalculate derived stats after changes
        this.recalculateStats();
    }

    advanceTime(monthsPassed: number, context?: { action?: string }, daysPassed: number = 0): { event: GameEvent | null; message?: string } {
        if (!this.state.alive) return { event: null, message: "已死亡" };

        // Turn Start Triggers
        this.triggerTalents('TURN_START');

        // [NEW] Time Advancement Logic
        // Normalize days to 30/month
        this.state.day = (this.state.day || 1) + daysPassed;
        let extraMonths = 0;
        while (this.state.day > 30) {
            this.state.day -= 30;
            extraMonths++;
        }

        const totalMonthsPassed = monthsPassed + extraMonths;
        this.state.months += totalMonthsPassed;

        const oldAge = this.state.age;
        this.state.age = Math.floor(this.state.months / 12);

        // [NEW] 气运buff倒计时
        this.tickFortuneBuffs(totalMonthsPassed);

        // Age Up Trigger
        if (this.state.age > oldAge) {
            this.triggerTalents('AGE_UP');
        }

        if (this.state.age >= this.getLifespan()) {
            this.state.alive = false;
            return { event: null, message: "寿元已尽，道消身死..." };
        }

        // Legacy Per Turn (Maintain for now)
        this.state.talents.forEach(t => {
            if (t.effect?.per_turn?.ALL) {
                for (const k in this.state.attributes) this.state.attributes[k] += t.effect.per_turn.ALL;
            }
        });

        // [NEW] Check Missions
        this.checkMissions();

        const breakthroughMsg = this.checkBreakthrough();
        const event = this.findEvent(context);

        // Turn End Triggers
        this.triggerTalents('TURN_END');

        return { event, message: breakthroughMsg };
    }

    init(selectedTalents: Talent[], initialAttributes: { [key: string]: number }) {
        this.state = this.getInitialState();
        this.state.months = 0;
        this.state.age = 0;

        this.state.attributes = { ...this.state.attributes, ...initialAttributes };
        this.state.talents = selectedTalents;

        // Apply talent initial effects (Legacy)
        selectedTalents.forEach(t => {
            if (t.effect) {
                this.applyEffect(t.effect);
                // [FIX] Handle history explicitly
                if (t.effect.history) {
                    this.state.history.push(t.effect.history);
                }
            }
        });

        // Apply PASSIVE modifiers
        this.triggerTalents('PASSIVE');

        // [NEW] Start First Mission if none active
        if (this.state.missions.active.length === 0 && this.state.missions.completed.length === 0) {
            this.startMission('MQ_01_SURVIVAL');
        }

        this.initLife();
    }



    reset() {
        this.state = this.getInitialState();
    }

    initLife() {
        // Determine Background based on LUCK
        const luck = this.state.attributes.LUCK || 0;
        // ... (Background logic same as before)
        if (luck < GAME_RULES.BACKGROUND_THRESHOLDS.FARMER) this.state.background = 'FARMER';
        else if (luck < GAME_RULES.BACKGROUND_THRESHOLDS.RICH) this.state.background = 'RICH';
        else this.state.background = 'CULTIVATOR';

        // Add Background Flag
        this.state.flags.push(`BG_${this.state.background}`);

        // Generate Parents based on Background
        const father = generateNPC('父亲', 'M');
        const mother = generateNPC('母亲', 'F');

        const bgKey = this.state.background as keyof typeof NPC_DESCRIPTIONS.FATHER;

        father.desc = NPC_DESCRIPTIONS.FATHER[bgKey];
        mother.desc = NPC_DESCRIPTIONS.MOTHER[bgKey];

        if (this.state.background === 'FARMER' || this.state.background === 'RICH') {
            father.realm = '凡人';
            mother.realm = '凡人';
        }

        this.state.relationships = [father, mother];

        // Generate Player Name (Inherit Surname)
        const surname = father.name.charAt(0);
        const givenName = generateName(this.state.gender === 'Male' ? 'M' : 'F').slice(1);
        this.state.name = surname + givenName;

        // Recalc Battle Stats for Player
        this.recalculateStats();

        // Initial Log
        this.state.history.push(TEXT_CONSTANTS.BIRTH_LOG + `父亲是${father.name}，母亲是${mother.name}。`);

        // Context-aware Naming
        const namer = NPC_DESCRIPTIONS.NAMER[bgKey] || TEXT_CONSTANTS.MYSTERIOUS_PERSON;
        this.state.history.push(`${namer}为你取名为：${this.state.name}。`);

        // Trigger specific Birth Event based on Background
        let birthEventId = '';
        if (this.state.background === 'FARMER') birthEventId = 'EVT_BIRTH_FARMER';
        else if (this.state.background === 'RICH') birthEventId = 'EVT_BIRTH_RICH';
        else birthEventId = 'EVT_BIRTH_001';

        const birthEvent = this.events.find(e => e.id === birthEventId);
        if (birthEvent) {
            this.processEvent(birthEvent);
        }

        // [NEW] 决定先天命格
        const talentIds = this.state.talents.map(t => t.id);
        this.state.fate = determineFate(this.state.attributes, this.state.background, talentIds);

        // [NEW] 生成新世界 (随机种子, 随机名称)
        const worldGen = new WorldGenerator({
            seed: Math.floor(Math.random() * 9999999),
        });
        this.state.world = worldGen.generate();

        // [NEW] 玩家出生地 (选择一个推荐境界最低的安全区域)
        const safeRegions = this.state.world.regions.sort((a, b) => a.dangerLevel - b.dangerLevel);
        const startRegion = safeRegions[0];
        this.state.location = startRegion.id;

        this.state.history.push(`你出生在${startRegion.name}，这里${startRegion.description}。`);
    }

    checkBreakthrough(): string | undefined {
        const idx = this.state.realm_idx;
        if (idx >= REALMS.length - 1) return;

        // [FIX] Constraint: Mortal -> Qi Refining requires Cultivation Method AND minimum age
        if (idx === 0) {
            if (!this.state.flags.includes('HAS_CULTIVATION_METHOD')) return;
            if (this.state.age < 5) return; // 婴幼儿不可能突破
        }

        const thresholds = GAME_RULES.REALM_THRESHOLDS;
        const power = (this.state.attributes.ROOT || 0) * 2 + (this.state.attributes.INT || 0) + (this.state.attributes.STR || 0);

        if (power > thresholds[idx]) {
            this.state.realm_idx++;
            const bonus = (idx + 1) * GAME_RULES.REALM_BONUS_MULTIPLIER;
            for (const k in this.state.attributes) {
                this.state.attributes[k] += bonus;
            }
            // Signal breakthrough pending UI state? For now just return message
            // Future: set state.breakthroughPending = true;
            return `突破成功！晋升为【${REALMS[this.state.realm_idx]}】！全属性 +${bonus}`;
        }
    }

    findEvent(context?: { action?: string }): GameEvent | null {
        // 1. Update World State (Eras)
        this.updateWorldState();

        // 2. Filter candidates
        const candidates = this.events.filter(e => {
            if (this.state.triggeredEvents.includes(e.id)) return false;

            // A. Unified Condition Check (V2)
            if (e.conditions && !ConditionMatcher.checkConditions(this.state, e.conditions, context)) {
                return false;
            }

            // Probability Check (V2)
            if (e.probability !== undefined && Math.random() > e.probability) {
                return false;
            }

            // B. Backward Compatibility (Legacy Fields)

            // Age
            if (e.age !== undefined && e.age !== this.state.age) return false;

            // Stats (Legacy reqStats)
            if (e.reqStats) {
                for (const [key, val] of Object.entries(e.reqStats)) {
                    if ((this.state.attributes[key] || 0) < val) return false;
                }
            }

            // Flags
            if (e.reqFlags) {
                if (!e.reqFlags.every(f => this.state.flags.includes(f))) return false;
            }
            if (e.forbidFlags) {
                if (e.forbidFlags.some(f => this.state.flags.includes(f))) return false;
            }

            // Gender/Race
            if (e.reqGender && e.reqGender !== this.state.gender) return false;
            if (e.reqRace && e.reqRace !== this.state.race) return false;
            if (e.reqRealm && REALMS[this.state.realm_idx] !== e.reqRealm) return false;

            // Trigger (Legacy Eval - Deprecated but kept for now)
            if (e.trigger && !this.checkCondition(e.trigger, context)) return false;

            return true;
        });

        if (candidates.length === 0) return null;

        // Weighted random based on LUCK? For now just uniform
        return candidates[Math.floor(Math.random() * candidates.length)];
    }

    updateWorldState() {
        this.state.world.worldMonth++;
        // TODO: Implement Era progression logic here
    }

    checkCondition(cond: string, context?: { action?: string }): boolean {
        // [DEPRECATED] formatting legacy string triggers 
        // This method should be removed once all data is migrated to V2 'conditions'
        try {
            const scope = {
                stats: this.state.attributes,
                age: this.state.age,
                flags: this.state.flags,
                background: this.state.background,
                realm_idx: this.state.realm_idx,
                action: context?.action || ''
            };

            // Simple substitutions to avoid full eval if possible (Optimization)
            if (cond === "true") return true;

            const func = new Function('s', `
                with (s) {
                    return ${cond};
                }
            `);
            return !!func(scope);
        } catch (e) {
            console.warn(`[GameEngine] Trigger Eval Failed: "${cond}"`, e);
            return false;
        }
    }

    processEvent(event: GameEvent) {
        // V2 Branch Logic with Unified Matcher
        if (event.branches && event.branches.length > 0) {
            for (const branch of event.branches) {
                // Determine Outcome using Unified Matcher
                const isSuccess = ConditionMatcher.checkConditions(this.state, branch.check);
                const outcome = isSuccess ? branch.success : branch.failure;

                // Apply Outcome & Capture Changes
                const changes = this.applyOutcome(outcome);

                this.state.triggeredEvents.push(event.id);

                // Build Log Text
                let logText = `${event.title || ''}: ${outcome.text}`;
                if (changes.length > 0) {
                    logText += `\n( ${changes.join('，')} )`;
                }
                // [FIX] Explicitly append history from effect
                if (outcome.effect?.history) {
                    logText += `\n${outcome.effect.history}`;
                }

                // Push to History
                const currentMonth = this.state.months % 12;
                const timeStr = currentMonth > 0 ? `[${this.state.age}岁${currentMonth}月]` : `[${this.state.age}岁]`;
                this.state.history.push(`${timeStr} ${logText}`);

                return;
            }
        }

        // Legacy / Standard Processing
        const changes: string[] = [];
        if (event.effect) {
            changes.push(...this.applyEffect(event.effect));
        }
        this.state.triggeredEvents.push(event.id);

        const title = event.title;
        const body = event.content || "";

        let logText = "";
        if (title) {
            logText = `${title}: ${body}`;
        } else {
            logText = body || "突发事件";
        }

        // Append changes
        if (changes.length > 0) {
            logText += `\n( ${changes.join('，')} )`;
        }
        // [FIX] Explicitly append history from effect
        if (event.effect?.history) {
            logText += `\n${event.effect.history}`;
        }

        const currentMonth = this.state.months % 12;
        const timeStr = currentMonth > 0 ? `[${this.state.age}岁${currentMonth}月]` : `[${this.state.age}岁]`;

        this.state.history.push(`${timeStr} ${logText}`);
    }

    applyOutcome(outcome: import('../types').EventOutcome): string[] {
        const changes: string[] = [];
        if (outcome.effect) {
            changes.push(...this.applyEffect(outcome.effect));
        }
        if (outcome.death) {
            this.state.alive = false;
        }
        return changes;
    }

    makeChoice(choice: EventChoice) {
        const currentMonth = this.state.months % 12;
        const timeStr = currentMonth > 0 ? `[${this.state.age}岁${currentMonth}月]` : `[${this.state.age}岁]`;

        // [FIX] Log the choice text
        let logText = `你选择了：${choice.text}`;

        if (choice.effect) {
            const changes = this.applyEffect(choice.effect);
            if (changes.length > 0) {
                logText += `\n( ${changes.join('，')} )`;
            }
            // [FIX] Append history from effect
            if (choice.effect.history) {
                logText += `\n${choice.effect.history}`;
            }
        }
        this.state.history.push(`${timeStr} ${logText}`);
    }

    applyEffect(effect: Effect): string[] {
        const changes: string[] = [];
        if (!effect) return changes;

        // Stats (Generic & Specific)
        for (const k in effect) {
            if (k === 'flags' || k === 'history' || k === 'stats' || k === 'per_turn' || k === 'items' || k === 'item') continue;

            if (typeof effect[k] === 'number') {
                const val = effect[k];
                this.state.attributes[k] = (this.state.attributes[k] || 0) + val;
                const statName = TEXT_CONSTANTS.STATS[k as keyof typeof TEXT_CONSTANTS.STATS] || k;
                changes.push(`${statName} ${val > 0 ? '+' : ''}${val}`);
            }
        }

        // Legacy/Structured Stats support
        if (effect.stats) {
            for (const k in effect.stats) {
                const val = effect.stats[k];
                this.state.attributes[k] = (this.state.attributes[k] || 0) + val;
                const statName = TEXT_CONSTANTS.STATS[k as keyof typeof TEXT_CONSTANTS.STATS] || k;
                changes.push(`${statName} ${val > 0 ? '+' : ''}${val}`);
            }
        }

        this.recalculateStats();

        // Special flags
        if (effect.flags) {
            this.state.flags.push(...effect.flags);
        }

        // [FIX] Items handling (Moved here to ensure changes are returned)
        if (effect.item) {
            this.addItem(effect.item, 1);
            const itemName = ITEMS[effect.item]?.name || effect.item;
            changes.push(`获得 ${itemName}`);
        }
        if (effect.items) {
            effect.items.forEach(id => {
                this.addItem(id, 1);
                const itemName = ITEMS[id]?.name || id;
                changes.push(`获得 ${itemName}`);
            });
        }

        // [FIX] Removed implicit history push. Caller must handle effect.history.
        // if (effect.history) {
        //     this.state.history.push(effect.history);
        // }

        // [NEW] Check Missions
        this.checkMissions();

        return changes;
    }

    // --- 气运Buff管理 ---
    tickFortuneBuffs(monthsPassed: number) {
        const expired: FortuneBuff[] = [];
        this.state.fortuneBuffs = this.state.fortuneBuffs.filter(buff => {
            buff.remainingMonths -= monthsPassed;
            if (buff.remainingMonths <= 0) {
                expired.push(buff);
                return false;
            }
            return true;
        });

        // 过期时撤销属性加成并记录日志
        for (const buff of expired) {
            for (const [k, v] of Object.entries(buff.effects)) {
                this.state.attributes[k] = (this.state.attributes[k] || 0) - v;
            }
            const timeStr = `[${this.state.age}岁]`;
            this.state.history.push(`${timeStr} 「${buff.name}」气运消散了…`);
        }
    }

    addFortuneBuff(buff: Omit<FortuneBuff, 'remainingMonths'> & { remainingMonths?: number }) {
        // 检查是否已存在
        const existing = this.state.fortuneBuffs.find(b => b.id === buff.id);
        if (existing) {
            existing.remainingMonths = buff.durationMonths; // 刷新时间
            return;
        }

        const fullBuff: FortuneBuff = {
            ...buff,
            remainingMonths: buff.remainingMonths ?? buff.durationMonths
        };

        this.state.fortuneBuffs.push(fullBuff);

        // 应用属性加成
        for (const [k, v] of Object.entries(fullBuff.effects)) {
            this.state.attributes[k] = (this.state.attributes[k] || 0) + v;
        }

        const timeStr = `[${this.state.age}岁]`;
        const effectsStr = Object.entries(fullBuff.effects).map(([k, v]) => {
            const name = TEXT_CONSTANTS.STATS[k as keyof typeof TEXT_CONSTANTS.STATS] || k;
            return `${name} ${v > 0 ? '+' : ''}${v}`;
        }).join('，');
        this.state.history.push(`${timeStr} 获得气运「${fullBuff.name}」（持续${fullBuff.durationMonths}月）\n${effectsStr}`);
    }

    // [NEW] Travel Logic
    travelTo(targetId: string): { success: boolean; message: string } {
        const currentId = this.state.location;
        if (currentId === targetId) return { success: false, message: '你已经在这里了。' };

        const endNode = this.getLocationEntity(targetId);
        if (!endNode) return { success: false, message: '无效的目标地点。' };

        const travelDays = this.calculateTravelDays(targetId);

        // Simple processing: accumlate days into months
        const monthsPassed = Math.max(0, Math.floor(travelDays / 30));

        this.state.world.worldMonth += monthsPassed;
        this.state.location = targetId;

        // If cross month, trigger updates
        if (monthsPassed > 0) {
            // this.updateWorldState();
        }

        const log = `你前往${endNode.name}，路途遥远，耗时 ${travelDays} 天。`;
        this.state.history.push(log);

        // [NEW] Loot Check (Simple)
        if (Math.random() < 0.3) { // 30% chance
            const lootTable = LOOT_TABLES['LOW_LEVEL'];
            const roll = Math.random() * 100;
            let currentWeight = 0;

            for (const item of lootTable) {
                currentWeight += item.weight;
                if (roll <= currentWeight) {
                    const count = Math.floor(Math.random() * (item.max - item.min + 1)) + item.min;
                    this.addItem(item.itemId, count);
                    const itemName = ITEMS[item.itemId]?.name || '未知物品';
                    this.state.history.push(`你在途中偶然发现：${itemName} x${count}！`);
                    break;
                }
            }
        }

        return { success: true, message: log };
    }

    // --- Location Actions ---
    gather(): { success: boolean; message: string } {
        // Validation: Can only gather in wild/resource spots?
        const locationId = this.state.location;
        const locationEntity = this.getLocationEntity(locationId);

        // Simple check: If it's a Region and not a "City" type (we don't have City type on Region yet, but Location has type)
        // Let's assume all NON-City Locations are gatherable for now, plus Regions.
        // Actually, let's just allow gathering everywhere except Cities for simplicity?
        // Or better: Check if it is a Location with type 'CITY'.

        let isSafeZone = false;
        if (locationEntity && 'type' in locationEntity && (locationEntity.type === 'CITY' || locationEntity.type === 'SECT')) {
            isSafeZone = true;
        }

        if (isSafeZone) {
            return { success: false, message: '这里是安全区，无法通过采集获取资源。' };
        }

        // Consume Time
        const daysCost = 5;
        this.advanceTime(Math.floor(daysCost / 30), { action: 'gather' }); // Approximate month advancement? 
        // advanceTime takes months. 5 days is ~0.16 months. 
        // Our system runs on months. Maybe gathering takes 1 month? 
        // Or we track days separately? Currently state.age is derived from months.
        // Let's make gathering take 1 month for now to simplify, or add a 'days' accumulator.
        // For now: 1 Month cost.
        this.state.world.worldMonth += 1;
        this.state.months += 1;
        // Trigger generic turn updates
        this.triggerTalents('TURN_START');
        this.triggerTalents('TURN_END'); // Simple turn skip

        // Loot Logic
        const lootTable = LOOT_TABLES['LOW_LEVEL']; // Default to low level
        // In future: select table based on region danger level

        const roll = Math.random() * 100;
        let currentWeight = 0;
        let lootItem: string | null = null;
        let lootCount = 0;

        for (const item of lootTable) {
            currentWeight += item.weight;
            if (roll <= currentWeight) {
                lootCount = Math.floor(Math.random() * (item.max - item.min + 1)) + item.min;
                lootItem = item.itemId;
                break;
            }
        }

        if (lootItem) {
            this.addItem(lootItem, lootCount);
            const itemName = ITEMS[lootItem]?.name || '未知物品';
            const msg = `你在附近搜寻了一番，发现了：${itemName} x${lootCount}`;
            this.state.history.push(`[${this.state.age}岁] ${msg}`);
            return { success: true, message: msg };
        } else {
            const msg = '你在附近搜寻了一番，但一无所获。';
            this.state.history.push(`[${this.state.age}岁] ${msg}`);
            return { success: true, message: msg };
        }
    }

    rest(): { success: boolean; message: string } {
        // Validation: Must be in a City or Sect
        const locationId = this.state.location;
        const locationEntity = this.getLocationEntity(locationId);

        let canRest = false;
        if (locationEntity && 'type' in locationEntity && (locationEntity.type === 'CITY' || locationEntity.type === 'SECT')) {
            canRest = true;
        }

        if (!canRest) {
            return { success: false, message: '只有在城镇或宗门才能安全休息。' };
        }

        const cost = 5; // Spirit Stones
        const currentStones = this.state.inventory.find(s => s.itemId === 'spirit_stone')?.count || 0;

        if (currentStones < cost) {
            return { success: false, message: `灵石不足，客栈住宿需要 ${cost} 灵石。` };
        }

        this.removeItem('spirit_stone', cost);

        // Full Heal
        this.state.battleStats.HP = this.state.battleStats.MAX_HP;
        this.state.battleStats.MP = this.state.battleStats.MAX_MP;

        // Pass Time (1 Month)
        this.state.world.worldMonth += 1;
        this.state.months += 1;
        this.triggerTalents('TURN_START');
        this.triggerTalents('TURN_END');

        const msg = `你花费 ${cost} 灵石在客栈休整了一月，精气神已恢复巅峰。`;
        this.state.history.push(`[${this.state.age}岁] ${msg}`);

        return { success: true, message: msg };
    }

    getLocationEntity(id: string): Region | Location | null {
        // Search Regions
        const region = this.state.world.regions.find(r => r.id === id);
        if (region) return region;

        // Search Locations inside Regions
        for (const r of this.state.world.regions) {
            const loc = r.locations.find(l => l.id === id);
            if (loc) return loc;
        }
        return null;
    }

    // --- Inventory System ---
    addItem(itemId: string, count: number) {
        if (count <= 0) return;
        const itemDef = ITEMS[itemId];
        if (!itemDef) {
            console.warn(`Attempted to add unknown item: ${itemId}`);
            return;
        }

        const existingSlot = this.state.inventory.find(s => s.itemId === itemId);
        if (existingSlot && itemDef.stackable) {
            existingSlot.count += count;
        } else {
            this.state.inventory.push({ itemId, count });
        }
        // Log? Maybe too spammy for every add, rely on event logs
    }

    removeItem(itemId: string, count: number): boolean {
        const slotIdx = this.state.inventory.findIndex(s => s.itemId === itemId);
        if (slotIdx === -1) return false;

        if (this.state.inventory[slotIdx].count < count) return false;

        this.state.inventory[slotIdx].count -= count;
        if (this.state.inventory[slotIdx].count <= 0) {
            this.state.inventory.splice(slotIdx, 1);
        }
        return true;
    }

    // --- Travel System ---
    calculateTravelDays(targetId: string): number {
        const currentLocationId = this.state.location;
        const currentEntity = this.getLocationEntity(currentLocationId);
        const targetEntity = this.getLocationEntity(targetId);

        if (!currentEntity || !targetEntity) return 999;

        // Calculate Distance
        // If same region: Distance = Euclidean Distance of locations
        // If different region: Distance = Distance to Region Center + Region Distance + Distance from Region Center
        // Simplified: Global Coordinate System (Region * 20 + Local)

        const getGlobalCoord = (entity: Region | Location) => {
            if ('locations' in entity) {
                // It's a Region
                return { x: entity.coord.x * 20, y: entity.coord.y * 20 };
            } else {
                // It's a Location
                // Find parent region
                const region = this.state.world.regions.find(r => r.id === (entity as any).regionId || r.locations.some(l => l.id === entity.id));
                if (!region) return { x: 0, y: 0 };
                return {
                    x: region.coord.x * 20 + entity.coord.x,
                    y: region.coord.y * 20 + entity.coord.y
                };
            }
        };

        const start = getGlobalCoord(currentEntity);
        const end = getGlobalCoord(targetEntity);

        const dist = Math.sqrt(Math.pow(end.x - start.x, 2) + Math.pow(end.y - start.y, 2));

        // Speed: 
        // Base Speed = 20 (Li/Day). 
        // Modified by Move Speed (Li/Day).
        const speed = this.state.battleStats.MOVE_SPEED || 20;

        // Map Scale: 1 Unit = 10 Li? 
        // Let's say 1 Unit = 100 Li.
        const distanceLi = dist * 100;

        const days = Math.ceil(distanceLi / speed);
        return Math.max(1, days);
    }

    useItem(itemId: string): { success: boolean; message: string } {
        const slot = this.state.inventory.find(s => s.itemId === itemId);
        if (!slot) return { success: false, message: '你没有该物品。' };

        const itemDef = ITEMS[itemId];
        if (!itemDef) return { success: false, message: '物品定义不存在。' };
        if (itemDef.type !== 'CONSUMABLE') return { success: false, message: '该物品无法直接使用。' };

        // Consume 1
        this.removeItem(itemId, 1);

        // Apply Effect
        if (itemDef.effect) {
            const changes = this.applyEffect(itemDef.effect);
            let msg = `使用了[${itemDef.name}]。`;
            if (changes.length > 0) {
                msg += `\n( ${changes.join('，')} )`;
            }
            if (itemDef.effect.history) {
                msg += `\n${itemDef.effect.history}`;
            }
            return { success: true, message: msg };
        }

        return { success: true, message: `使用了[${itemDef.name}]，感觉什么也没发生。` };
    }

    // --- Combat System ---
    startCombat(enemyId: string, enemyName: string, enemyStats: BattleStats) {
        // Initialize Combat State
        const playerStats = this.state.battleStats;

        this.state.minigame = this.state.minigame || {};
        this.state.minigame.combat = {
            isActive: true,
            turn: 0,
            maxTurns: 20, // Limit turns to prevent infinite loops
            player: {
                name: this.state.name || '道友',
                maxHp: playerStats.MAX_HP,
                currentHp: playerStats.HP || playerStats.MAX_HP,
                stats: { ...playerStats }
            },
            enemy: {
                id: enemyId,
                name: enemyName,
                maxHp: enemyStats.MAX_HP,
                currentHp: enemyStats.HP || enemyStats.MAX_HP,
                stats: { ...enemyStats }
            },
            logs: [],
            result: null
        };

        this.state.history.push(`[${this.state.age}岁] 遭遇强敌【${enemyName}】，战斗一触即发！`);

        // Start Combat Loop (Interval? Or Tick based?)
        // For visual effect, we use a tick system driven by UI or Engine Interval.
        // Let's use a self-contained loop for now, but UI needs time to render.
        // We can expose a `combatTick` method and call it via setInterval in UI or Engine's update loop.
        // For simplicity, let's auto-resolve for now OR allow UI to drive it?
        // User wants "progress bar collision", implying real-time or visual turn-based.
        // Let's use a standard interval in the UI/Overlay to call `engine.combatTick()`.
    }

    combatTick() {
        const combat = this.state.minigame?.combat;
        if (!combat || !combat.isActive || combat.result) return;

        combat.turn += 1;
        const turn = combat.turn;
        const p = combat.player;
        const e = combat.enemy;

        // Simple Turn Logic: Speed check? 
        // For now: Simultaneous attack

        // Player Action
        const pDmg = Math.max(1, p.stats.ATK - e.stats.DEF);
        const pCrit = Math.random() < (p.stats.CRIT || 0) / 100;
        const finalPDmg = Math.floor(pDmg * (pCrit ? 1.5 : 1.0));

        e.currentHp -= finalPDmg;
        combat.logs.push({ turn, message: `你对${e.name}造成了 ${finalPDmg}${pCrit ? '(暴击)' : ''} 点伤害。` });

        // Check Enemy Death
        if (e.currentHp <= 0) {
            e.currentHp = 0;
            combat.result = 'WIN';
            this.endCombat(true);
            return;
        }

        // Enemy Action
        const eDmg = Math.max(1, e.stats.ATK - p.stats.DEF);
        const eCrit = Math.random() < (e.stats.CRIT || 0) / 100;
        const finalEDmg = Math.floor(eDmg * (eCrit ? 1.5 : 1.0));

        p.currentHp -= finalEDmg;
        combat.logs.push({ turn, message: `${e.name}对你造成了 ${finalEDmg}${eCrit ? '(暴击)' : ''} 点伤害。` });

        // Update Real Player HP
        this.state.battleStats.HP = p.currentHp;

        // Check Player Death
        if (p.currentHp <= 0) {
            p.currentHp = 0;
            combat.result = 'LOSE';
            this.endCombat(false);
            return;
        }

        // Turn Limit
        if (combat.turn >= combat.maxTurns) {
            combat.result = 'ESCAPE';
            combat.logs.push({ turn, message: '战斗陷入僵局，双方各自退去。' });
            this.endCombat(null); // Draw/Run
        }
    }

    endCombat(win: boolean | null) {
        const combat = this.state.minigame?.combat;
        if (!combat) return;

        combat.isActive = false;

        if (win === true) {
            // Rewards
            const exp = 100; // Placeholder
            this.addSpiritStones(10); // Placeholder
            this.state.history.push(`战胜了${combat.enemy.name}，获得了战利品。`);
        } else if (win === false) {
            this.state.history.push(`你不敌${combat.enemy.name}，身受重伤，仓皇逃窜。`);
            // Penalty?
        } else {
            this.state.history.push('战斗结束，双方平手。');
        }

        // Clear combat state after delay happens in UI
        // But for data, we mark inactive.
    }

    // Helper
    addSpiritStones(amount: number) {
        // ... (Already have addItem?)
        this.addItem('spirit_stone', amount);
    }
    // --- Mission System ---

    checkMissions() {
        const activeMissions = this.state.missions.active;
        // Iterate backwards to allow safe removal
        for (let i = activeMissions.length - 1; i >= 0; i--) {
            const missionState = activeMissions[i];
            const def = MAIN_QUESTS.find(m => m.id === missionState.id);
            if (!def) continue;

            let allObjectivesMet = true;
            let stateChanged = false;

            // Check Objectives
            for (const obj of def.objectives) {
                let currentVal = 0;

                switch (obj.type) {
                    case 'STAT':
                        // Check Attributes (Attributes are flat now)
                        currentVal = (this.state.attributes[obj.target] || 0);
                        break;
                    case 'AGE':
                        currentVal = this.state.age;
                        break;
                    case 'REALM':
                        currentVal = this.state.realm_idx;
                        break;
                    case 'ITEM':
                        // Count items in inventory
                        const count = this.state.inventory.reduce((sum, slot) => slot.itemId === obj.target ? sum + slot.count : sum, 0);
                        currentVal = count;
                        break;
                    case 'LOCATION':
                        // Check if cur location matches target
                        currentVal = this.state.location === obj.target ? 1 : 0;
                        break;
                    case 'EVENT':
                        // Check if event ID is in triggeredEvents
                        currentVal = this.state.triggeredEvents.includes(obj.target) ? 1 : 0;
                        break;
                    case 'SECT':
                        // Check if joined any sect (target='ANY') or specific sect
                        if (obj.target === 'ANY') {
                            currentVal = this.state.sect ? 1 : 0;
                        } else {
                            currentVal = this.state.sect === obj.target ? 1 : 0;
                        }
                        break;
                }

                // Update Progress locally
                if (missionState.objectives[obj.id] !== currentVal) {
                    missionState.objectives[obj.id] = currentVal;
                    stateChanged = true;
                }

                if (currentVal < obj.requiredCount) {
                    allObjectivesMet = false;
                }
            }

            if (allObjectivesMet) {
                this.completeMission(missionState, def);
            }
        }
    }

    completeMission(missionState: import('../types/missionTypes').GenericMissionState, def: Mission) {
        // 1. Move to Completed
        this.state.missions.active = this.state.missions.active.filter(m => m.id !== missionState.id);
        this.state.missions.completed.push(missionState.id);

        // 2. Grant Rewards
        const rewards = def.rewards;
        let rewardLog = `完成任务 [${def.title}]！`;

        if (rewards && rewards.effect) {
            const changes = this.applyEffect(rewards.effect);
            if (changes.length > 0) {
                rewardLog += `\n获得: ${changes.join('，')}`;
            }
        }

        // Log completion
        const currentMonth = this.state.months % 12;
        const timeStr = currentMonth > 0 ? `[${this.state.age}岁${currentMonth}月]` : `[${this.state.age}岁]`;
        this.state.history.push(`${timeStr} ${rewardLog}`);
        // Also trigger event flavor text?
        if (def.endDialog) {
            this.state.history.push(`${timeStr} ${def.endDialog}`);
        }

        // 3. Chain Next Mission
        if (def.nextMissionId) {
            this.startMission(def.nextMissionId);
        }
    }

    startMission(missionId: string) {
        // ID Check
        if (this.state.missions.active.some(m => m.id === missionId) ||
            this.state.missions.completed.includes(missionId)) {
            return; // Already active or done
        }

        const def = MAIN_QUESTS.find(m => m.id === missionId);
        if (!def) return;

        // Requirements Check (Prereq logic can go here)
        if (def.minAge && this.state.age < def.minAge) return;

        // Init State
        const newState: import('../types/missionTypes').GenericMissionState = {
            id: missionId,
            status: 'ACTIVE',
            objectives: {}
        };

        // Init Objectives Map
        def.objectives.forEach(obj => {
            newState.objectives[obj.id] = 0;
        });

        this.state.missions.active.push(newState);

        // Log Start
        const currentMonth = this.state.months % 12;
        const timeStr = currentMonth > 0 ? `[${this.state.age}岁${currentMonth}月]` : `[${this.state.age}岁]`;
        this.state.history.push(`${timeStr} 开启新任务: [${def.title}]`);
        // Force immediate check in case conditions are already met
        this.checkMissions();
    }
}

/**
 * 世界生成器
 * 
 * 核心流程：seed → RNG → 分步生成 → WorldSnapshot
 * 
 * 生成顺序：
 * 1. 纪元
 * 2. 区域 (含地形、灵气、危险度)
 * 3. 宗门 (含道统、阵营、等级)
 * 4. 安置宗门到区域
 * 5. 世界NPC (宗主/长老/弟子/散修)
 * 6. 资源节点
 * 7. 宗门关系网络
 * 8. 区域邻接关系
 */

import type {
    WorldConfig, WorldSnapshot, Region, Location, Sect,
    WorldNPC, ResourceNode, SectRelation,
    TerrainType, Alignment, Doctrine, SectRank, SectPosition,
    LocationType, Coordinate,
} from '../types/worldTypes';
import { DEFAULT_WORLD_CONFIG } from '../types/worldTypes';
import { SeededRandom } from '../utils/SeededRandom';
import { REALMS } from '../types';
import {
    SECT_NAME_PREFIX, SECT_NAME_SUFFIX,
    REGION_NAME_PREFIX, REGION_NAME_SUFFIX,
    TERRAIN_TEMPLATES, LOCATION_TEMPLATES,
    DOCTRINE_TEMPLATES, SECT_RANK_TEMPLATES,
    POSITION_TEMPLATES, RESOURCE_NAMES,
    NPC_TITLES, PERSONALITY_TAGS, ERA_TEMPLATES,
    LOCATION_DESCRIPTORS,
} from '../modules/xianxia/data/worldTemplates';
import { generateName } from '../utils/DataUtils';

// ─── 辅助名称池 ─── (用于地点名随机字)
const LOCATION_CHAR_POOL = '灵玄幽碧苍翠寒焰云雾星月龙凤瑶琼仙古太清紫金赤黑'.split('');

export class WorldGenerator {
    private rng: SeededRandom;
    private config: WorldConfig;
    private options: { silent: boolean };

    constructor(config?: Partial<WorldConfig>, options: { silent?: boolean } = {}) {
        this.config = { ...DEFAULT_WORLD_CONFIG, ...config };
        this.options = { silent: false, ...options };

        if (this.config.seed === 0) {
            this.config.seed = Math.floor(Math.random() * 0x7FFFFFFF);
        }
        this.rng = new SeededRandom(this.config.seed);

        // 如果未指定名称，随机生成一个
        if (!config?.name) {
            this.config.name = this.generateRandomWorldName();
        }
    }

    private generateRandomWorldName(): string {
        const prefix = this.rng.pick(['玄黄', '紫薇', '太虚', '万古', '神荒', '灵源', '九幽', '苍穹', '星罗', '混沌']);
        const suffix = this.rng.pick(['界', '大陆', '域', '天', '星', '神州']);
        return prefix + suffix;
    }

    /** 生成完整世界快照 */
    generate(): WorldSnapshot {
        if (!this.options.silent) {
            console.log(`[WorldGen] 种子: ${this.config.seed}, 开始生成世界「${this.config.name}」...`);
        }

        // 1. 纪元
        const era = this.generateEra();
        if (!this.options.silent) console.log(`[WorldGen] 纪元: ${era.name}`);

        // 2. 区域
        const regions = this.generateRegions();
        if (!this.options.silent) console.log(`[WorldGen] 区域: ${regions.length} 个`);

        // 3. 宗门
        const sects = this.generateSects();
        if (!this.options.silent) console.log(`[WorldGen] 宗门: ${sects.length} 个`);

        // 4. 安置宗门
        this.placeSects(regions, sects);

        // 5. 世界NPC
        const worldNPCs = this.generateWorldNPCs(sects, regions);
        if (!this.options.silent) console.log(`[WorldGen] 世界NPC: ${worldNPCs.length} 个`);

        // 6. 资源节点
        const resourceNodes = this.generateResourceNodes(regions);
        if (!this.options.silent) console.log(`[WorldGen] 资源节点: ${resourceNodes.length} 个`);

        // 7. 宗门关系
        this.establishRelations(sects);

        // 8. 区域邻接
        this.linkRegions(regions);

        // 9. 为宗门生成驻地地点
        this.generateSectHeadquarters(regions, sects);

        const snapshot: WorldSnapshot = {
            config: { ...this.config },
            name: this.config.name || '苍穹大陆',
            era,
            regions,
            sects,
            worldNPCs,
            resourceNodes,
            worldMonth: 0,
            globalLuck: 50,
            activeWorldEvents: [],
            pastWorldEvents: [],
        };

        if (!this.options.silent) {
            console.log(`[WorldGen] 世界「${snapshot.name}」生成完毕!`);
        }
        return snapshot;
    }

    // ═══════════════════════════════════════
    //  Step 1: 纪元
    // ═══════════════════════════════════════

    private generateEra() {
        const template = ERA_TEMPLATES.find(e => e.id === this.config.startingEra)
            || this.rng.pick(ERA_TEMPLATES);
        return { ...template };
    }

    // ═══════════════════════════════════════
    //  Step 2: 区域
    // ═══════════════════════════════════════

    private generateRegions(): Region[] {
        const regions: Region[] = [];
        const terrainWeights = TERRAIN_TEMPLATES.map(t => t.weight);
        const terrainTypes = TERRAIN_TEMPLATES.map(t => t);
        const usedNames = new Set<string>();

        // 布局参数
        const centerX = 50;
        const centerY = 50;
        const radius = 35; // 大陆半径

        for (let i = 0; i < this.config.regionCount; i++) {
            const template = this.rng.weightedPick(terrainTypes, terrainWeights);
            const name = this.generateRegionName(template.type, usedNames);
            usedNames.add(name);

            // 坐标生成：第一个区域在中心，其余环绕
            let coord: Coordinate;
            if (i === 0) {
                coord = { x: centerX, y: centerY };
            } else {
                const angle = ((i - 1) / (this.config.regionCount - 1)) * Math.PI * 2;
                // 添加随机扰动 (Jitter)
                const jitterX = this.rng.nextInt(-5, 5);
                const jitterY = this.rng.nextInt(-5, 5);
                coord = {
                    x: Math.round(centerX + Math.cos(angle) * radius + jitterX),
                    y: Math.round(centerY + Math.sin(angle) * radius + jitterY)
                };
            }

            const spiritVar = this.rng.nextFloat(-0.3, 0.3);
            const dangerVar = this.rng.nextInt(-2, 2);

            const region: Region = {
                id: this.rng.uid('reg'),
                name,
                terrain: template.type,
                coord,
                description: `${name}，${this.describeRegion(template.type)}`,
                spiritDensity: Math.max(0.1, +(template.baseSpiritDensity * this.config.spiritDensityMultiplier + spiritVar).toFixed(2)),
                dangerLevel: Math.max(1, Math.min(10, template.baseDangerLevel + dangerVar)),
                recommendedRealm: Math.min(REALMS.length - 1, Math.max(0, Math.floor((template.baseDangerLevel + dangerVar) / 2))),
                locations: [],
                controlledBy: [],
                adjacentRegions: [],
            };

            // 每个区域生成 2~5 个子地点
            const locCount = this.rng.nextInt(2, 5);
            for (let j = 0; j < locCount; j++) {
                // 地点坐标：在区域中心周围随机分布
                const locAngle = this.rng.next() * Math.PI * 2;
                const locRadius = this.rng.nextInt(3, 12); // 区域内半径
                const locCoord = {
                    x: Math.round(region.coord.x + Math.cos(locAngle) * locRadius),
                    y: Math.round(region.coord.y + Math.sin(locAngle) * locRadius)
                };

                // 边界检查 (0-100)
                locCoord.x = Math.max(2, Math.min(98, locCoord.x));
                locCoord.y = Math.max(2, Math.min(98, locCoord.y));

                const locTemplate = this.rng.weightedPick(
                    LOCATION_TEMPLATES,
                    LOCATION_TEMPLATES.map(t => t.weight)
                );
                const locName = this.generateLocationName(locTemplate.namePatterns);
                const loc: Location = {
                    id: this.rng.uid('loc'),
                    name: locName,
                    type: locTemplate.type,
                    coord: locCoord,
                    description: this.rng.pick(LOCATION_DESCRIPTORS[locTemplate.type] || ['未知之地']),
                    regionId: region.id,
                    level: Math.max(1, Math.min(10, region.dangerLevel + this.rng.nextInt(-1, 1))),
                    discovered: locTemplate.type === 'CITY', // 坊市默认已探索
                    resourceIds: [],
                };
                region.locations.push(loc);
            }

            regions.push(region);
        }

        return regions;
    }

    private generateRegionName(terrain: TerrainType, used: Set<string>): string {
        const suffixes = REGION_NAME_SUFFIX[terrain];
        let name: string;
        let attempts = 0;
        do {
            name = this.rng.pick(REGION_NAME_PREFIX) + this.rng.pick(suffixes);
            attempts++;
        } while (used.has(name) && attempts < 20);
        return name;
    }

    private generateLocationName(patterns: string[]): string {
        const pattern = this.rng.pick(patterns);
        const char = this.rng.pick(LOCATION_CHAR_POOL) + this.rng.pick(LOCATION_CHAR_POOL);
        return pattern.replace('{地名}', char);
    }

    private describeRegion(terrain: TerrainType): string {
        const descs: Record<TerrainType, string[]> = {
            MOUNTAIN: ['高耸入云的山脉，灵气充沛', '连绵不绝的群峰，常有修仙者出没'],
            PLAINS: ['一望无际的平原，适宜凡人生活', '沃野千里，灵气稀薄但物产丰富'],
            FOREST: ['古树参天的密林，暗藏菁英灵兽', '终年雾霭弥漫的神秘丛林'],
            DESERT: ['黄沙漫天的荒漠，寸草不生', '炽热干燥的沙海，偶有遗迹浮现'],
            SWAMP: ['瘴气弥漫的沼泽，毒虫横行', '幽暗阴冷的泽地，深处暗藏凶险'],
            OCEAN: ['浩瀚无垠的海域，深处有龙族遗迹', '波涛汹涌的灵海，岛屿星罗棋布'],
            VOLCANO: ['岩浆翻涌的火域，蕴含罕见灵矿', '终年喷发的火山群，危险至极'],
            SNOW: ['终年积雪的寒域，灵气凛冽纯净', '冰天雪地的极寒之境，常有寒属灵材'],
            ABYSS: ['暗无天日的深渊，魔气冲天', '连通冥界的虚空裂缝，凶险万分'],
        };
        return this.rng.pick(descs[terrain]);
    }

    // ═══════════════════════════════════════
    //  Step 3: 宗门
    // ═══════════════════════════════════════

    private generateSects(): Sect[] {
        const sects: Sect[] = [];
        const usedNames = new Set<string>();

        // 按配置比例分配正邪
        const evilCount = Math.round(this.config.sectCount * this.config.evilFactionRatio);
        const righteousCount = Math.round(this.config.sectCount * 0.4);
        const neutralCount = this.config.sectCount - evilCount - righteousCount;

        const alignments: Alignment[] = [
            ...Array(righteousCount).fill('RIGHTEOUS' as Alignment),
            ...Array(neutralCount).fill('NEUTRAL' as Alignment),
            ...Array(evilCount).fill('EVIL' as Alignment),
        ];
        this.rng.shuffle(alignments);

        for (let i = 0; i < this.config.sectCount; i++) {
            const alignment = alignments[i] || 'NEUTRAL';

            // 选择道统 (考虑阵营偏好)
            const doctrine = this.pickDoctrine(alignment);

            // 选择等级
            const rankTemplate = this.rng.weightedPick(
                SECT_RANK_TEMPLATES,
                SECT_RANK_TEMPLATES.map(t => t.weight)
            );

            // 生成名称
            const name = this.generateSectName(alignment, usedNames);
            usedNames.add(name);

            const power = this.rng.nextInt(rankTemplate.powerRange[0], rankTemplate.powerRange[1]);

            const sect: Sect = {
                id: this.rng.uid('sect'),
                name,
                rank: rankTemplate.rank,
                alignment,
                doctrine,
                description: this.generateSectDescription(name, doctrine, alignment, rankTemplate.rank),
                power,
                reputation: this.rng.nextInt(10, power),
                leaderId: '', // 由 NPC 生成步骤填充
                elderIds: [],
                discipleIds: [],
                headquarterRegionId: '', // 由安置步骤填充
                territoryRegionIds: [],
                relations: [],
                traits: this.generateSectTraits(doctrine, alignment),
                entryRealmRequirement: Math.max(0, Math.floor(rankTemplate.minLeaderRealm / 2)),
                treasury: this.rng.nextInt(power * 100, power * 500),
            };

            sects.push(sect);
        }

        return sects;
    }

    private pickDoctrine(alignment: Alignment): Doctrine {
        // 根据阵营对道统做加权
        const filtered = DOCTRINE_TEMPLATES.map(d => {
            let w = d.weight;
            if (alignment === 'EVIL' && d.righteousBias > 0.6) w *= 0.2;
            if (alignment === 'EVIL' && d.righteousBias < 0.3) w *= 3;
            if (alignment === 'RIGHTEOUS' && d.righteousBias < 0.3) w *= 0.1;
            if (alignment === 'RIGHTEOUS' && d.righteousBias > 0.6) w *= 2;
            return { item: d.doctrine, weight: w };
        });
        return this.rng.weightedPick(
            filtered.map(f => f.item),
            filtered.map(f => f.weight)
        );
    }

    private generateSectName(alignment: Alignment, used: Set<string>): string {
        let name: string;
        let attempts = 0;
        do {
            // 邪派偏好用邪道前缀(池后半段)
            const prefixPool = alignment === 'EVIL'
                ? SECT_NAME_PREFIX.slice(Math.floor(SECT_NAME_PREFIX.length * 0.6))
                : SECT_NAME_PREFIX.slice(0, Math.floor(SECT_NAME_PREFIX.length * 0.8));
            name = this.rng.pick(prefixPool) + this.rng.pick(SECT_NAME_SUFFIX);
            attempts++;
        } while (used.has(name) && attempts < 30);
        return name;
    }

    private generateSectDescription(name: string, doctrine: Doctrine, alignment: Alignment, rank: SectRank): string {
        const docLabel = DOCTRINE_TEMPLATES.find(d => d.doctrine === doctrine)?.label || '修仙';
        const rankLabel = SECT_RANK_TEMPLATES.find(r => r.rank === rank)?.label || '宗门';
        const alignLabel = alignment === 'RIGHTEOUS' ? '正道' : alignment === 'EVIL' ? '魔道' : '中立';
        return `${name}，${alignLabel}${rankLabel}，以${docLabel}为尊。`;
    }

    private generateSectTraits(doctrine: Doctrine, alignment: Alignment): string[] {
        const docLabel = DOCTRINE_TEMPLATES.find(d => d.doctrine === doctrine)?.label || '修仙';
        const alignLabel = alignment === 'RIGHTEOUS' ? '正道' : alignment === 'EVIL' ? '魔道' : '中立';
        const extra = this.rng.pick(['底蕴深厚', '新锐崛起', '隐世不出', '广纳门徒', '唯才是举', '严苛门规']);
        return [docLabel, alignLabel, extra];
    }

    // ═══════════════════════════════════════
    //  Step 4: 安置宗门到区域
    // ═══════════════════════════════════════

    private placeSects(regions: Region[], sects: Sect[]): void {
        // 按实力排序，强宗优先选地盘
        const sorted = [...sects].sort((a, b) => b.power - a.power);

        for (const sect of sorted) {
            // 寻找最适合的区域
            const scored = regions.map(r => {
                const terrain = TERRAIN_TEMPLATES.find(t => t.type === r.terrain);
                let score = 0;

                // 阵营匹配
                if (terrain?.suitableAlignments.includes(sect.alignment)) score += 30;

                // 道统地形匹配
                const docTemplate = DOCTRINE_TEMPLATES.find(d => d.doctrine === sect.doctrine);
                if (docTemplate?.preferredTerrains.includes(r.terrain)) score += 20;

                // 灵气浓度高的区域更受欢迎
                score += r.spiritDensity * 10;

                // 避免过度拥挤
                score -= r.controlledBy.length * 15;

                // 随机扰动
                score += this.rng.nextFloat(-5, 5);

                return { region: r, score };
            });

            scored.sort((a, b) => b.score - a.score);
            const best = scored[0].region;

            sect.headquarterRegionId = best.id;
            sect.territoryRegionIds = [best.id];
            best.controlledBy.push(sect.id);

            // 大宗门/圣地占据多个区域
            if (sect.rank === 'LARGE' || sect.rank === 'HOLY_LAND') {
                const extraCount = sect.rank === 'HOLY_LAND' ? 2 : 1;
                const available = scored.slice(1, 1 + extraCount * 2);
                for (let i = 0; i < Math.min(extraCount, available.length); i++) {
                    sect.territoryRegionIds.push(available[i].region.id);
                    available[i].region.controlledBy.push(sect.id);
                }
            }
        }
    }

    // ═══════════════════════════════════════
    //  Step 5: 世界NPC
    // ═══════════════════════════════════════

    private generateWorldNPCs(sects: Sect[], regions: Region[]): WorldNPC[] {
        const npcs: WorldNPC[] = [];
        let remaining = this.config.worldNPCCount;

        // 为每个宗门生成核心成员
        for (const sect of sects) {
            const rankTemplate = SECT_RANK_TEMPLATES.find(r => r.rank === sect.rank)!;
            const leaderRealm = Math.max(rankTemplate.minLeaderRealm, this.rng.nextInt(rankTemplate.minLeaderRealm, Math.min(REALMS.length - 1, rankTemplate.minLeaderRealm + 2)));

            // 宗主
            const leader = this.createWorldNPC(sect, 'SECT_MASTER', leaderRealm, sect.headquarterRegionId);
            npcs.push(leader);
            sect.leaderId = leader.id;
            remaining--;

            // 长老
            const elderCount = this.rng.nextInt(rankTemplate.elderRange[0], rankTemplate.elderRange[1]);
            for (let i = 0; i < elderCount && remaining > 0; i++) {
                const pos: SectPosition = i === 0 ? 'GRAND_ELDER' : 'ELDER';
                const offset = POSITION_TEMPLATES.find(p => p.position === pos)?.realmOffset || -1;
                const realm = Math.max(0, leaderRealm + offset + this.rng.nextInt(-1, 0));
                const elder = this.createWorldNPC(sect, pos, realm, sect.headquarterRegionId);
                npcs.push(elder);
                sect.elderIds.push(elder.id);
                remaining--;
            }

            // 弟子
            const discipleCount = this.rng.nextInt(2, Math.min(6, rankTemplate.memberRange[1] - elderCount - 1));
            for (let i = 0; i < discipleCount && remaining > 0; i++) {
                const pos: SectPosition = this.rng.chance(0.4) ? 'INNER_DISCIPLE' : 'OUTER_DISCIPLE';
                const offset = POSITION_TEMPLATES.find(p => p.position === pos)?.realmOffset || -3;
                const realm = Math.max(0, leaderRealm + offset + this.rng.nextInt(-1, 1));
                const disc = this.createWorldNPC(sect, pos, realm, sect.headquarterRegionId);
                npcs.push(disc);
                sect.discipleIds.push(disc.id);
                remaining--;
            }
        }

        // 剩余名额 → 散修
        while (remaining > 0) {
            const region = this.rng.pick(regions);
            const realm = this.rng.nextInt(0, Math.min(3, REALMS.length - 1));
            const wanderer = this.createWorldNPC(null, 'WANDERER', realm, region.id);
            npcs.push(wanderer);
            remaining--;
        }

        return npcs;
    }

    private createWorldNPC(
        sect: Sect | null,
        position: SectPosition,
        realmIndex: number,
        regionId: string,
    ): WorldNPC {
        const gender = this.rng.chance(0.5) ? 'M' as const : 'F' as const;
        const alignment = sect?.alignment || this.rng.pick(['RIGHTEOUS', 'NEUTRAL', 'EVIL'] as Alignment[]);

        // 年龄与境界相关
        const baseAge = 20 + realmIndex * 30 + this.rng.nextInt(0, 50);
        const lifespan = 60 + realmIndex * 80 + this.rng.nextInt(0, 40);

        // 战力 = 境界 * 100 + 随机
        const combatPower = realmIndex * 100 + this.rng.nextInt(-20, 50);

        // 性格标签
        const tags = PERSONALITY_TAGS[alignment] || PERSONALITY_TAGS.NEUTRAL;
        const personality = this.rng.pickN(tags, this.rng.nextInt(1, 3));

        // 称号 (高境界NPC)
        let title: string | undefined;
        if (realmIndex >= 4 && sect) {
            const titlePool = NPC_TITLES[sect.doctrine] || [];
            if (titlePool.length > 0) title = this.rng.pick(titlePool);
        }

        return {
            id: this.rng.uid('npc'),
            name: generateName(gender),
            gender,
            title,
            realmIndex,
            age: baseAge,
            lifespan,
            alive: true,
            sectId: sect?.id || null,
            position,
            regionId,
            alignment,
            personality,
            combatPower: Math.max(1, combatPower),
            knownToPlayer: false,
            playerFavor: 0,
        };
    }

    // ═══════════════════════════════════════
    //  Step 6: 资源节点
    // ═══════════════════════════════════════

    private generateResourceNodes(regions: Region[]): ResourceNode[] {
        const nodes: ResourceNode[] = [];
        let remaining = this.config.resourceNodeCount;

        for (const region of regions) {
            const terrain = TERRAIN_TEMPLATES.find(t => t.type === region.terrain);
            if (!terrain) continue;

            // 每个区域至少 1 个资源，最多按比例
            const count = Math.max(1, Math.round(remaining / Math.max(1, regions.length - regions.indexOf(region))));
            const actual = Math.min(count, remaining, this.rng.nextInt(1, 4));

            for (let i = 0; i < actual; i++) {
                const resType = this.rng.pick(terrain.resourceTypes);
                const namePool = RESOURCE_NAMES[resType] || ['未知资源'];
                const name = this.rng.pick(namePool);

                const node: ResourceNode = {
                    id: this.rng.uid('res'),
                    name,
                    type: resType,
                    description: `位于${region.name}的${name}`,
                    regionId: region.id,
                    level: Math.max(1, Math.min(10, region.dangerLevel + this.rng.nextInt(-1, 1))),
                    yield: +this.rng.nextFloat(0.5, 2.0).toFixed(2),
                    controlled: region.controlledBy.length > 0 && this.rng.chance(0.6),
                    controllerId: region.controlledBy.length > 0 ? this.rng.pick(region.controlledBy) : undefined,
                    depleted: false,
                };

                nodes.push(node);

                // 将资源关联到区域的某地点
                if (region.locations.length > 0) {
                    const loc = this.rng.pick(region.locations);
                    loc.resourceIds.push(node.id);
                }

                remaining--;
                if (remaining <= 0) break;
            }
            if (remaining <= 0) break;
        }

        return nodes;
    }

    // ═══════════════════════════════════════
    //  Step 7: 宗门关系
    // ═══════════════════════════════════════

    private establishRelations(sects: Sect[]): void {
        for (let i = 0; i < sects.length; i++) {
            for (let j = i + 1; j < sects.length; j++) {
                const a = sects[i];
                const b = sects[j];

                let favorability = 0;

                // 阵营影响
                if (a.alignment === b.alignment) favorability += 30;
                if (a.alignment === 'RIGHTEOUS' && b.alignment === 'EVIL') favorability -= 60;
                if (a.alignment === 'EVIL' && b.alignment === 'RIGHTEOUS') favorability -= 60;

                // 道统影响 (同道统竞争)
                if (a.doctrine === b.doctrine) favorability -= 15;

                // 地盘冲突
                const sharedTerritory = a.territoryRegionIds.some(id => b.territoryRegionIds.includes(id));
                if (sharedTerritory) favorability -= 20;

                // 随机扰动
                favorability += this.rng.nextInt(-20, 20);

                // 钳制到 [-100, 100]
                favorability = Math.max(-100, Math.min(100, favorability));

                const type: SectRelation['type'] =
                    favorability > 40 ? 'ALLIANCE' :
                        favorability < -40 ? 'HOSTILE' :
                            favorability > 10 ? 'TRADE' : 'NEUTRAL';

                a.relations.push({ targetSectId: b.id, favorability, type });
                b.relations.push({ targetSectId: a.id, favorability, type });
            }
        }
    }

    // ═══════════════════════════════════════
    //  Step 8: 区域邻接
    // ═══════════════════════════════════════

    private linkRegions(regions: Region[]): void {
        // 简单链式 + 随机交叉连接
        for (let i = 0; i < regions.length; i++) {
            // 链式连接
            if (i + 1 < regions.length) {
                const a = regions[i];
                const b = regions[i + 1];
                if (!a.adjacentRegions.includes(b.id)) a.adjacentRegions.push(b.id);
                if (!b.adjacentRegions.includes(a.id)) b.adjacentRegions.push(a.id);
            }

            // 随机交叉（约30%几率与另一个非相邻区域连接）
            if (this.rng.chance(0.3) && regions.length > 3) {
                const other = this.rng.pick(regions.filter(r => r.id !== regions[i].id && !regions[i].adjacentRegions.includes(r.id)));
                if (other) {
                    regions[i].adjacentRegions.push(other.id);
                    other.adjacentRegions.push(regions[i].id);
                }
            }
        }

        // 首尾连通 (环形世界)
        if (regions.length > 2) {
            const first = regions[0];
            const last = regions[regions.length - 1];
            if (!first.adjacentRegions.includes(last.id)) {
                first.adjacentRegions.push(last.id);
                last.adjacentRegions.push(first.id);
            }
        }
    }

    // ═══════════════════════════════════════
    //  Step 9: 宗门驻地地点
    // ═══════════════════════════════════════

    private generateSectHeadquarters(regions: Region[], sects: Sect[]): void {
        for (const sect of sects) {
            const region = regions.find(r => r.id === sect.headquarterRegionId);
            if (!region) continue;

            // 坐标：在区域中心附近，尽量不与现有地点重叠
            // 简单起见，随机一个偏移
            const angle = this.rng.next() * Math.PI * 2;
            const dist = this.rng.nextInt(4, 10);
            const hqCoord = {
                x: Math.round(region.coord.x + Math.cos(angle) * dist),
                y: Math.round(region.coord.y + Math.sin(angle) * dist)
            };

            // 边界检查
            hqCoord.x = Math.max(2, Math.min(98, hqCoord.x));
            hqCoord.y = Math.max(2, Math.min(98, hqCoord.y));

            const hqLoc: Location = {
                id: this.rng.uid('loc'),
                name: `${sect.name}山门`,
                type: 'SECT_HQ',
                coord: hqCoord,
                description: `${sect.name}的总部所在，${this.rng.pick(LOCATION_DESCRIPTORS['SECT_HQ'])}`,
                regionId: region.id,
                level: Math.min(10, Math.floor(sect.power / 10)),
                discovered: false,
                sectId: sect.id,
                resourceIds: [],
            };

            region.locations.push(hqLoc);
        }
    }
}

import { create } from 'zustand';
import { persist, createJSONStorage } from 'zustand/middleware';
import { GameEngine } from '../engine/GameEngine';
import { type PlayerState, type GameEvent, type Talent, type SaveMeta, type EventChoice, REALMS } from '../types';
import { TALENTS } from '../modules/xianxia/data/talents';
import { EVENTS } from '../modules/xianxia/data/events';
import { XianxiaConfig } from '../modules/xianxia/config';
import { META_UPGRADES } from '../data/meta';
import { ActionSystem } from '../engine/systems/ActionSystem';

// Import other stores for cross-store interaction
import { useUIStore } from './uiStore';
import { useMetaStore } from './metaStore';

// Type moved to uiStore, but keeping here if needed for type reference or refactor module
// type GameScene = ... (Managed by UIStore)

// --- SAVE SYSTEM VERSIONING ---
const SAVE_VERSION = 1;

// Migration Helper
// eslint-disable-next-line @typescript-eslint/no-explicit-any
function migrateSave(data: any, targetVersion: number): any {
  let currentVersion = data.version || 0;

  // Migration Chain
  if (currentVersion < 1) {
    // v0 -> v1: Ensure 'flags', 'world', and 'inventory' exist
    console.log("Migrating Save v0 -> v1");
    if (!data.gameState) data.gameState = {};
    if (!data.gameState.flags) data.gameState.flags = [];
    if (!data.gameState.inventory) data.gameState.inventory = [];
    if (!data.gameState.relationships) data.gameState.relationships = [];

    // World might be missing in very old saves, if so, we can't fully restore, 
    // but we can ensure it doesn't crash by adding a dummy world or regenerating.
    // For now, let's assume if world is missing, it's a broken save, 
    // BUT we can try to inject a default generated one if we had access to WorldGenerator here.
    // Since we don't easily, we'll initialize empty objects to prevent crash.
    if (!data.gameState.world) {
      console.warn("Save missing world data, initializing empty structure to prevent immediate crash.");
      data.gameState.world = { regions: [], sects: [], worldMonth: 0 };
    }

    currentVersion = 1;
  }

  // Future migrations:
  // if (currentVersion < 2) { ... }

  data.version = currentVersion;
  return data;
}

interface GameStore {
  engine: GameEngine;
  gameState: PlayerState;

  currentEvent: GameEvent | null;
  breakthroughMsg: string | null;

  // Game Flow State
  availableTalents: Talent[];
  selectedTalentIds: string[];
  allocStats: { [key: string]: number };
  availablePoints: number;
  statsConfirmed: boolean;

  talentResetCount: number;

  // Actions
  saveGame: (slotId?: number) => void;
  loadGame: (slotId: number) => boolean;
  getSlots: () => SaveMeta;
  deleteSave: (slotId: number) => void;
  currentSlot: number | null;
  // hasSave: () => boolean; // Deprecated
  startGame: () => void;
  drawTalents: () => void;
  resetTalents: () => void;
  selectTalent: (id: string) => void;
  confirmTalents: () => void;
  updateStat: (key: string, delta: number) => void;
  autoAllocate: (mode: 'RANDOM' | 'AVG') => void;
  confirmStats: () => void;

  // Engine Proxy
  nextTurn: () => void;
  performAction: (actionType: 'WORK' | 'CULTIVATE' | 'EXPLORE' | 'GROW' | 'STUDY_LIT' | 'STUDY_MARTIAL') => void;
  makeChoice: (choice: EventChoice) => void;
  ackBreakthrough: () => void;
  travel: (targetId: string) => { success: boolean; message: string };
}

export const useGameStore = create<GameStore>()(
  persist(
    (set, get) => {
      // Initialize GameEngine
      const engine = new GameEngine(XianxiaConfig, EVENTS, TALENTS, {
        name: "无名氏",
        gender: Math.random() > 0.5 ? 'Male' : 'Female',
        age: 0,
        months: 0,
        realm_idx: 0,
        attributes: {}, // Will be filled by config
        battleStats: {
          MAX_HP: 100, MAX_MP: 0, ATK: 10, DEF: 10, SPD: 10, CRIT: 0
        },

        talents: [],
        flags: [],
        relationships: [],
        partners: [],
        pets: [],
        home: {
          level: 1,
          name: '破旧草屋',
          modules: [],
          resources: { 'spirit_stones': 0 }
        },
        professions: {
          alchemy: { level: 0, exp: 0, maxExp: 100 },
          artifact: { level: 0, exp: 0, maxExp: 100 },
          formation: { level: 0, exp: 0, maxExp: 100 },
          talisman: { level: 0, exp: 0, maxExp: 100 }
        },
        inventory: [],
        triggeredEvents: [],
        history: [],
        alive: true,
        background: 'FARMER', // Default

        // World Context
        world: {
          era: {
            id: 'ERA_RECOVERY',
            name: '灵气复苏',
            description: '天地灵气开始逐渐复苏，修仙者数量激增。',
            luckModifier: 10,
            spiritDensity: 1.2
          },
          globalLuck: 50,
          worldMonth: 0,
          activeWorldEvents: []
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
        } as any, // Cast to any because we provide partial world state that Engine will fill

        // [NEW] Personality & Acquired Traits
        personality: {
          // Core Values (-100 to 100)
          'JUSTICE': 0, // Pos: Justice, Neg: Evil
          'COURAGE': 0, // Pos: Brave, Neg: Timid
          'AMBITION': 0 // Pos: Ambitious, Neg: Content
        },
        acquiredTraits: []
      });

      return {
        engine,
        gameState: engine.state,
        currentEvent: null,
        breakthroughMsg: null,

        talentResetCount: 0,

        availableTalents: [],
        selectedTalentIds: [],
        allocStats: { STR: 0, INT: 0, CHR: 0, POT: 0, LUCK: 0 },
        availablePoints: 20,
        statsConfirmed: false,

        // --- Persistence (Multi-Slot) ---
        currentSlot: null as number | null,

        getSlots: (): SaveMeta => {
          try {
            const metaJson = localStorage.getItem('aeon_save_meta');
            if (metaJson) {
              const meta = JSON.parse(metaJson);
              // Ensure version exists in meta, defaults to 0 if missing
              if (meta.version === undefined) meta.version = 0;
              return meta;
            }

            // Migration Check: If no meta but legacy save exists
            const legacy = localStorage.getItem('aeon_save');
            if (legacy) {
              const legacyData = JSON.parse(legacy);
              const meta: SaveMeta = {
                version: 1, // Legacy migration counts as v1
                lastPlayedSlot: 0,
                slots: {
                  0: {
                    timestamp: legacyData.timestamp || Date.now(),
                    name: legacyData.gameState?.name || "无名氏",
                    summary: `凡人 · ${Math.floor((legacyData.gameState?.months || 0) / 12)}岁`,
                    empty: false
                  }
                }
              };
              // Move legacy to slot 0 and upgrade to v1
              const migratedLegacy = migrateSave(legacyData, 1);
              localStorage.setItem('aeon_save_0', JSON.stringify(migratedLegacy));
              localStorage.setItem('aeon_save_meta', JSON.stringify(meta));
              localStorage.removeItem('aeon_save');
              return meta;
            }

            // Default empty
            return { version: SAVE_VERSION, lastPlayedSlot: -1, slots: {} };
          } catch (e) {
            console.error("Save meta error", e);
            return { version: SAVE_VERSION, lastPlayedSlot: -1, slots: {} };
          }
        },

        saveGame: (slotId?: number) => {
          const { gameState, currentEvent, currentSlot } = get();
          const targetSlot = slotId !== undefined ? slotId : currentSlot;

          if (targetSlot === null || targetSlot === undefined) {
            console.error("No slot selected for saving");
            return;
          }

          const scene = useUIStore.getState().scene;
          const saveData = {
            version: SAVE_VERSION, // Validation Tag
            gameState,
            currentEvent,
            scene,
            timestamp: Date.now()
          };

          // Save Data
          localStorage.setItem(`aeon_save_${targetSlot}`, JSON.stringify(saveData));

          // Update Metadata
          const meta = get().getSlots();
          meta.lastPlayedSlot = targetSlot;
          meta.slots[targetSlot] = {
            timestamp: saveData.timestamp,
            name: gameState.name,
            summary: `${REALMS[gameState.realm_idx]} · ${gameState.age}岁`,
            empty: false
          };
          localStorage.setItem('aeon_save_meta', JSON.stringify(meta));

          set({ currentSlot: targetSlot });
          // alert('存档成功！'); // Removed alert for smoother flow, UI should show feedback
        },

        loadGame: (slotId: number) => {
          const json = localStorage.getItem(`aeon_save_${slotId}`);
          if (!json) return false;

          try {
            let data = JSON.parse(json);

            // Auto-Migrate on Load
            // If save has no version, assume 0. If it has version < SAVE_VERSION, migrate.
            const dataVersion = data.version || 0;
            if (dataVersion < SAVE_VERSION) {
              console.log(`[Store] Migrating save from v${dataVersion} to v${SAVE_VERSION}`);
              data = migrateSave(data, SAVE_VERSION);
              // Optional: Auto-save migrated version immediately? 
              // Better not to overwrite until user manually saves or auto-save triggers, 
              // but for stability let's keep it in memory.
            }

            const { engine } = get();

            // Restore Engine State
            engine.state = data.gameState;

            // Safety checks for critical objects
            if (!engine.state.attributes) engine.state.attributes = {};
            if (!engine.state.flags) engine.state.flags = [];
            // Ensure world exists (Migration should have handled this, but double check)
            if (!engine.state.world) {
              console.error("Save state missing world data even after migration!");
              return false;
            }

            // Restore Store State
            set({
              gameState: data.gameState,
              currentEvent: data.currentEvent,
              breakthroughMsg: null,
              currentSlot: slotId
            });

            // Restore UI Scene
            if (data.scene) {
              useUIStore.getState().setScene(data.scene);
            }

            // Update Meta Last Played
            const meta = get().getSlots();
            meta.lastPlayedSlot = slotId;
            localStorage.setItem('aeon_save_meta', JSON.stringify(meta));

            return true;
          } catch (e) {
            console.error("Load failed", e);
            // alert("存档损坏或版本不兼容！"); 
            return false;
          }
        },

        deleteSave: (slotId: number) => {
          console.log(`[Store] Deleting save slot ${slotId}`);
          localStorage.removeItem(`aeon_save_${slotId}`);
          const meta = get().getSlots();
          if (meta.slots[slotId]) {
            delete meta.slots[slotId];
            if (meta.lastPlayedSlot === slotId) meta.lastPlayedSlot = -1;
            localStorage.setItem('aeon_save_meta', JSON.stringify(meta));
            console.log(`[Store] Meta updated`, meta);
          } else {
            console.warn(`[Store] Slot ${slotId} not found in meta to delete`);
          }
        },

        startGame: () => {
          const { engine } = get();
          engine.reset();
          set({
            gameState: engine.state,
            currentEvent: null,
            breakthroughMsg: null,
            talentResetCount: 0,
            availableTalents: [],
            selectedTalentIds: [],
            allocStats: { STR: 0, INT: 0, CHR: 0, POT: 0, LUCK: 0 },
            availablePoints: 20,
            statsConfirmed: false,
            currentSlot: null // Clear slot until saved
          });
          useUIStore.getState().setScene('TALENT');
          get().drawTalents();
        },

        resetTalents: () => {
          const { talentResetCount, drawTalents } = get();
          const metaState = useMetaStore.getState().metaState;

          // Base resets = 3, + Meta Upgrades
          const maxResets = 3 + (metaState.unlockedUpgrades['meta_resets'] || 0);

          if (talentResetCount < maxResets) {
            set({ talentResetCount: talentResetCount + 1 });
            drawTalents();
          }
        },

        drawTalents: () => {
          // Config: 6 Options
          // Weights: White 55, Green 30, Blue 10, Purple 5, Orange 1, Red 0.03
          const WEIGHTS = [
            { grade: 1, weight: 5500 },  // White
            { grade: 2, weight: 3000 },  // Green
            { grade: 3, weight: 1000 },  // Blue
            { grade: 4, weight: 500 },   // Purple
            { grade: 5, weight: 100 },   // Orange
            { grade: 6, weight: 3 }      // Red
          ];
          const TOTAL_WEIGHT = 10103;

          const drawn: Talent[] = [];
          const drawnIds = new Set<string>();

          // Draw 6 times
          for (let i = 0; i < 6; i++) {
            let attempts = 0;
            let talent: Talent | undefined;

            while (!talent && attempts < 10) {
              attempts++;
              // 1. Roll Grade
              let roll = Math.floor(Math.random() * TOTAL_WEIGHT);
              let targetGrade = 1;
              for (const w of WEIGHTS) {
                if (roll < w.weight) {
                  targetGrade = w.grade;
                  break;
                }
                roll -= w.weight;
              }

              // 2. Filter Pool
              // If pool is empty for that grade, fallback to Grade 1 (Common)
              let pool = TALENTS.filter(t => t.grade === targetGrade && !drawnIds.has(t.id));
              if (pool.length === 0) {
                pool = TALENTS.filter(t => t.grade === 1 && !drawnIds.has(t.id));
              }

              if (pool.length > 0) {
                talent = pool[Math.floor(Math.random() * pool.length)];
              }
            }

            if (talent) {
              drawn.push(talent);
              drawnIds.add(talent.id);
            }
          }

          set({ availableTalents: drawn, selectedTalentIds: [] });
        },

        selectTalent: (id: string) => {
          const { selectedTalentIds } = get();
          if (selectedTalentIds.includes(id)) {
            set({ selectedTalentIds: selectedTalentIds.filter(tid => tid !== id) });
          } else {
            if (selectedTalentIds.length < 3) {
              set({ selectedTalentIds: [...selectedTalentIds, id] });
            }
          }
        },

        confirmTalents: () => {
          if (get().selectedTalentIds.length === 0) return; // At least 1
          // 重置属性分配
          useUIStore.getState().setScene('ALLOC');
          set({
            availablePoints: 20,
            allocStats: { STR: 0, INT: 0, CHR: 0, POT: 0, LUCK: 0 },
          });
        },

        updateStat: (key: string, delta: number) => {
          const { allocStats, availablePoints } = get();
          if (delta > 0 && availablePoints > 0) {
            set({
              allocStats: { ...allocStats, [key]: allocStats[key] + 1 },
              availablePoints: availablePoints - 1
            });
          } else if (delta < 0 && allocStats[key] > 0) {
            set({
              allocStats: { ...allocStats, [key]: allocStats[key] - 1 },
              availablePoints: availablePoints + 1
            });
          }
        },

        autoAllocate: (mode: 'RANDOM' | 'AVG') => {
          // 每次自动分配都从头开始，重新分配全部点数
          const totalPoints = 20;
          const keys = Object.keys(get().allocStats);
          const newStats: { [key: string]: number } = {};
          keys.forEach(k => { newStats[k] = 0; });

          let points = totalPoints;

          if (mode === 'AVG') {
            const perStat = Math.floor(points / keys.length);
            keys.forEach(k => {
              newStats[k] = perStat;
              points -= perStat;
            });
            // 余数分配给第一个属性
            if (points > 0) newStats[keys[0]] += points;
          } else {
            // 随机分配
            while (points > 0) {
              const k = keys[Math.floor(Math.random() * keys.length)];
              newStats[k]++;
              points--;
            }
          }

          set({ allocStats: newStats, availablePoints: 0 });
        },

        confirmStats: () => {
          console.log("[Store] confirmStats called");
          const { engine, selectedTalentIds, allocStats, currentSlot } = get();
          const metaState = useMetaStore.getState().metaState; // Get from MetaStore

          // Finalize Init
          const finalTalents = TALENTS.filter(t => selectedTalentIds.includes(t.id));

          // Apply Meta Upgrades to Stats
          const finalStats = { ...allocStats };

          // Dynamic mapping from config
          META_UPGRADES.forEach(upgrade => {
            if (upgrade.statKey) {
              const level = metaState.unlockedUpgrades[upgrade.id] || 0;
              if (level > 0) {
                finalStats[upgrade.statKey] = (finalStats[upgrade.statKey] || 0) + level;
              }
            }
          });

          console.log("[Store] Initializing Engine", finalTalents, finalStats);
          engine.init(finalTalents, finalStats);

          useUIStore.getState().setScene('GAME');
          set({
            gameState: { ...engine.state },
            currentEvent: null,
            breakthroughMsg: null,
          });

          // Init Life is handled in engine.init
          // Sync back just to be sure
          set({ gameState: { ...engine.state } });

          console.log("[Store] Game Initialized", engine.state);

          // Auto-Save Initial State
          if (currentSlot !== null) {
            get().saveGame(currentSlot);
          }
        },

        // Unified Action Handler
        performAction: (actionType: 'WORK' | 'CULTIVATE' | 'EXPLORE' | 'GROW' | 'STUDY_LIT' | 'STUDY_MARTIAL') => {
          const { engine } = get();

          const system = new ActionSystem(engine);

          const result = system.perform(actionType);

          if (result.success) {
            set({
              gameState: { ...engine.state }, // Force update
              currentEvent: result.event || null,
              breakthroughMsg: result.message || null
            });
          }
        },

        nextTurn: () => {
          get().performAction('CULTIVATE');
        },

        makeChoice: (choice: EventChoice) => {
          const { engine } = get();
          engine.makeChoice(choice);
          set({
            currentEvent: null,
            gameState: { ...engine.state } // Sync state changes (logs, stats)
          });
          // get().nextTurn(); // Removed: Choice resolution shouldn't force a new turn/cultivation cycle
        },

        ackBreakthrough: () => {
          set({ breakthroughMsg: null });
        },

        travel: (targetId: string) => {
          const { engine } = get();
          const result = engine.travelTo(targetId);
          if (result.success) {
            set({ gameState: { ...engine.state } });
          }
          return result;
        }
      };
    },
    {
      name: 'aeon_session_v1', // Session Storage Key
