    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-fade-in p-4" onClick={handleClose}>
            {/* 主容器 */}
            <div className="w-full max-w-5xl h-[82vh] bg-ink border border-slate-700/50 shadow-[0_0_50px_rgba(0,0,0,0.8)] flex rounded-xl overflow-hidden relative"
                onClick={e => e.stopPropagation()}>

                {/* 装饰边框 */}
                <div className="absolute inset-0 pointer-events-none border border-white/5 rounded-xl z-20"></div>

                {/* 关闭按钮 */}
                <button onClick={handleClose}
                    className="absolute top-5 right-5 z-50 w-9 h-9 flex items-center justify-center rounded-full bg-slate-900/80 border border-slate-600 text-slate-400 hover:text-white hover:border-emerald-500 hover:bg-emerald-900/20 transition-all backdrop-blur-md group">
                    <svg className="w-4 h-4 group-hover:rotate-90 transition-transform duration-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" />
                    </svg>
                </button>

                {/* ─── 左侧：档案卡 ─── */}
                <div className="w-72 shrink-0 bg-slate-900/80 border-r border-slate-800/50 flex flex-col relative">
                    <div className="absolute inset-0 opacity-[0.03] bg-[url('/noise.png')] pointer-events-none"></div>
                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-emerald-900/30 to-transparent"></div>

                    {/* 头像 + 基本信息 */}
                    <div className="p-6 pb-3 flex flex-col items-center">
                        <div className="w-28 h-28 rounded-full border-2 border-slate-700/50 p-1.5 mb-4 relative group">
                            <div className="w-full h-full rounded-full bg-slate-800 overflow-hidden relative flex items-center justify-center shadow-inner">
                                <span className={`font-serif text-5xl select-none transition-colors duration-500 ${isNPC
                                    ? (gender === 'Female' ? 'text-rose-700 group-hover:text-rose-400' : 'text-sky-700 group-hover:text-sky-400')
                                    : 'text-slate-600 group-hover:text-jade'}`}>
                                    {name[0]}
                                </span>
                                <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
                                {/* 境界徽章 */}
                                <div className="absolute bottom-2 left-1/2 -translate-x-1/2 px-2.5 py-px bg-black/60 border border-slate-600/50 rounded-full backdrop-blur-md shadow-lg">
                                    <span className="text-[11px] font-serif text-emerald-400 tracking-widest">{realm}</span>
                                </div>
                            </div>
                            <div className="absolute inset-0 rounded-full border border-emerald-500/20 scale-110 opacity-0 group-hover:opacity-100 transition-all duration-700 animate-pulse-glow"></div>
                        </div>

                        <div className="text-center space-y-1.5 w-full relative z-10">
                            <h2 className="text-2xl font-serif font-bold text-slate-100 tracking-wider flex items-center justify-center gap-1.5">
                                {name}
                                <span className={`text-sm ${gender === 'Male' ? 'text-blue-400/70' : 'text-rose-400/70'}`}>
                                    {gender === 'Male' ? '♂' : '♀'}
                                </span>
                            </h2>
                            {/* NPC 关系 + 亲密度 */}
                            {isNPC && relation && (
                                <div className="flex items-center justify-center gap-2">
                                    <span className="text-[11px] px-2 py-0.5 bg-emerald-950/30 border border-emerald-800/30 rounded-full text-emerald-400 font-serif">{relation}</span>
                                    {intimacy !== null && (
                                        <span className={`text-[11px] flex items-center gap-0.5 ${intimacy > 60 ? 'text-rose-400' : 'text-slate-500'}`}>
                                            ♥ {intimacy}
                                        </span>
                                    )}
                                </div>
                            )}
                            <div className="text-xs font-mono text-slate-500 tracking-[0.15em] bg-slate-950/30 py-1 rounded border border-slate-800/30 mx-6">
                                {age}岁 / {lifespan}
