                                                            {Object.entries(f.effects).map(([k, v]) => (
                                                                <span key={k} className={`text-[10px] font-mono px-1.5 py-px rounded ${v > 0 ? 'text-emerald-400 bg-emerald-950/30' : 'text-red-400 bg-red-950/30'}`}>
                                                                    {k} {v > 0 ? '+' : ''}{v}
                                                                </span>
                                                            ))}
                                                        </div>
                                                    )}
                                                </div>
                                            ))}
                                        </div>
                                    ) : (
                                        <div className="text-sm text-slate-600 italic font-serif">
                                            {isNPC ? '无法窥探此人命格' : '命格未定'}
                                        </div>
                                    )}
                                </div>

                                {/* 后天气运（仅自己） */}
                                {!isNPC && (
                                    <div>
                                        <h3 className="flex items-center gap-3 text-base font-bold text-slate-300 mb-4 font-serif tracking-widest">
                                            <span className="w-1.5 h-5 bg-sky-500 rounded-full shadow-[0_0_8px_rgba(14,165,233,0.5)]"></span>
                                            后天气运
                                        </h3>
                                        {fortuneBuffs.length > 0 ? (
                                            <div className="space-y-2">
                                                {fortuneBuffs.map(buff => (
                                                    <div key={buff.id} className="flex items-center gap-3 bg-slate-900/40 border border-slate-800/50 rounded-lg p-3">
                                                        <GradeBadge grade={buff.grade} name={buff.name} small />
                                                        <div className="flex-1 h-1.5 bg-slate-800 rounded-full overflow-hidden">
                                                            <div className="h-full rounded-full transition-all duration-500"
                                                                style={{
                                                                    width: `${(buff.remainingMonths / buff.durationMonths) * 100}%`,
                                                                    background: FATE_GRADE_COLORS[buff.grade],
                                                                    opacity: 0.6,
                                                                }} />
                                                        </div>
                                                        <span className="text-[11px] text-slate-500 font-mono tabular-nums w-12 text-right">{buff.remainingMonths}月</span>
                                                    </div>
                                                ))}
                                            </div>
                                        ) : (
                                            <div className="text-sm text-slate-600 italic font-serif">暂无气运加持</div>
                                        )}
                                    </div>
                                )}

                                {/* 已获特质（仅自己） */}
                                {!isNPC && gameState.acquiredTraits && gameState.acquiredTraits.length > 0 && (
                                    <div>
                                        <h3 className="flex items-center gap-3 text-base font-bold text-slate-300 mb-4 font-serif tracking-widest">
                                            <span className="w-1.5 h-5 bg-indigo-500 rounded-full shadow-[0_0_8px_rgba(99,102,241,0.5)]"></span>
                                            后天特质
                                        </h3>
                                        <div className="flex flex-wrap gap-2">
                                            {gameState.acquiredTraits.map(t => (
                                                <div key={t.id} className="px-3 py-1.5 bg-indigo-950/20 border border-indigo-800/30 rounded-lg text-xs text-indigo-300 hover:border-indigo-500/40 transition-colors cursor-default" title={t.description}>
                                                    {t.name}
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}
                            </div>
                        )}

                        {/* ═══ 关系 Tab（仅自己）═══ */}
                        {activeTab === 'REL' && !isNPC && (
                            <div className="animate-fade-in">
                                <div className="grid grid-cols-2 gap-3">
                                    {gameState.relationships.map((npc) => {
                                        const inspectNPC = useUIStore.getState().inspectNPC;
                                        return (
                                            <div key={npc.id}
                                                onClick={() => inspectNPC(npc)}
                                                className="flex items-center gap-4 p-4 bg-slate-900/40 border border-slate-800 rounded-xl hover:border-emerald-500/30 transition-all hover:bg-emerald-950/5 group cursor-pointer">
                                                <div className={`w-12 h-12 rounded-full flex items-center justify-center font-serif text-xl bg-slate-950 border-2 ${npc.gender === 'F'
                                                    ? 'text-rose-400 border-rose-900/30 group-hover:border-rose-500/50'
                                                    : 'text-sky-400 border-sky-900/30 group-hover:border-sky-500/50'
                                                    } transition-colors shadow-lg`}>
                                                    {npc.name[0]}
                                                </div>
                                                <div className="flex-1 min-w-0 space-y-1">
                                                    <div className="flex justify-between items-baseline">
                                                        <span className="font-bold text-base text-slate-200 font-serif truncate group-hover:text-emerald-300 transition-colors">{npc.name}</span>
                                                        <span className="text-[10px] bg-slate-950 px-2 py-0.5 rounded text-slate-400 border border-slate-800 shrink-0 ml-2">{npc.relation}</span>
                                                    </div>
                                                    <div className="flex justify-between items-center text-xs text-slate-500 font-mono">
                                                        <span className="px-1.5 py-0.5 rounded bg-slate-800/50">{npc.realm || '凡人'}</span>
                                                        <div className="flex items-center gap-3">
                                                            <span>{npc.age}/{npc.lifespan}岁</span>
                                                            <span className={npc.intimacy > 60 ? 'text-rose-400' : 'text-slate-600'}>♥ {npc.intimacy}</span>
                                                        </div>
                                                    </div>
                                                </div>
                                                <span className="text-slate-700 text-xs opacity-0 group-hover:opacity-100 transition-opacity shrink-0">→</span>
                                            </div>
                                        );
                                    })}
                                    {gameState.relationships.length === 0 && (
                                        <div className="col-span-2 flex flex-col items-center justify-center py-16 text-slate-600 font-serif space-y-3 opacity-70">
                                            <div className="text-4xl filter grayscale opacity-50">🍃</div>
                                            <div className="tracking-widest">举世茫茫，暂无故人...</div>
                                        </div>
                                    )}
                                </div>
                            </div>
                        )}

                        {/* ═══ 技艺 Tab（仅自己）═══ */}
                        {activeTab === 'PROF' && !isNPC && (
                            <div className="grid grid-cols-2 gap-4 animate-fade-in">
                                {Object.entries(gameState.professions).map(([key, stats]) => (
                                    <div key={key} className="relative overflow-hidden bg-slate-900/40 border border-slate-700/50 rounded-xl p-5 group hover:border-emerald-500/30 hover:bg-emerald-950/10 transition-all duration-500">
                                        <div className="absolute -right-3 -bottom-3 text-7xl opacity-[0.03] font-serif font-black text-white group-hover:text-emerald-400 group-hover:opacity-[0.08] transition-all duration-500 pointer-events-none select-none">
                                            {{ 'alchemy': '丹', 'artifact': '器', 'formation': '阵', 'talisman': '符' }[key]}
                                        </div>
                                        <div className="flex justify-between items-start mb-4">
                                            <div>
                                                <h3 className="text-lg font-serif font-bold text-slate-200 group-hover:text-emerald-400 transition-colors tracking-widest">
                                                    {{ 'alchemy': '炼丹之道', 'artifact': '炼器之道', 'formation': '阵法之道', 'talisman': '符箓之道' }[key]}
                                                </h3>
                                                <p className="text-xs text-slate-500 mt-1 font-mono">Lv.{stats.level} · 入门</p>
                                            </div>
                                        </div>
                                        <div className="space-y-1.5">
                                            <div className="flex justify-between text-xs text-slate-500 font-mono">
                                                <span>修炼进度</span>
                                                <span className="group-hover:text-emerald-400 transition-colors">{stats.exp} / {stats.maxExp}</span>
                                            </div>
                                            <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
                                                <div className="h-full bg-emerald-500 shadow-[0_0_8px_#10b981] transition-all duration-1000 ease-out rounded-full" style={{ width: `${(stats.exp / stats.maxExp) * 100}%` }} />
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}

                        {/* ═══ 生平 Tab（仅自己）═══ */}
                        {activeTab === 'LOG' && !isNPC && (
                            <div className="animate-fade-in">
                                {gameState.history.length > 0 ? (
                                    <div className="space-y-1 max-h-[55vh] overflow-y-auto custom-scrollbar pr-2">
                                        {gameState.history.map((entry, i) => (
                                            <div key={i} className="flex gap-3 py-1.5 border-b border-slate-800/20 last:border-0 group hover:bg-slate-900/20 px-2 rounded transition-colors">
                                                <span className="text-[10px] text-slate-700 font-mono tabular-nums shrink-0 pt-0.5 w-6 text-right">{i + 1}</span>
                                                <span className="text-xs text-slate-400 leading-relaxed">{entry}</span>
                                            </div>
                                        ))}
                                    </div>
                                ) : (
                                    <div className="flex flex-col items-center justify-center h-full text-slate-600 space-y-4 opacity-60">
                                        <div className="text-4xl">📜</div>
                                        <div className="font-serif tracking-[0.3em]">尚无记载</div>
                                    </div>
                                )}
                            </div>
                        )}

                        {/* Fallback for missing tabs */}
                        {!['ATTR', 'FATE', 'REL', 'PROF', 'LOG'].includes(activeTab) && (
                            <div className="flex flex-col items-center justify-center h-full text-slate-600 space-y-4 opacity-60 animate-fade-in">
                                <div className="w-16 h-16 border-2 border-dashed border-slate-700 rounded-full flex items-center justify-center text-3xl">🚧</div>
                                <div className="font-serif tracking-[0.3em] text-lg">功能修缮中</div>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

import { useMetaStore } from '../store/metaStore';
import { useUIStore } from '../store/uiStore';
import { META_UPGRADES } from '../data/meta';

export const ReincarnationHall = () => {
    const { metaState, purchaseUpgrade, loadMeta } = useMetaStore();

    // Ensure meta is loaded on mount (though store usually loads it)
    // useEffect(() => { loadMeta(); }, []); 

    const getCost = (upgrade: typeof META_UPGRADES[0], level: number) => {
        return upgrade.baseCost + (level * upgrade.costScale);
    };

    return (
        <div className="w-full h-full flex flex-col items-center relative overflow-hidden bg-void">
            {/* Background Decor */}
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,_var(--tw-gradient-stops))] from-amber-900/10 via-void/90 to-void pointer-events-none"></div>

            {/* Header */}
            <div className="shrink-0 pt-12 pb-6 text-center z-10 space-y-4 w-full flex flex-col items-center">
                <div className="text-xs font-mono text-amber-500 tracking-[0.5em] uppercase opacity-60">
                    命运节点
                </div>
                <h2 className="text-5xl font-serif font-bold text-transparent bg-clip-text bg-gradient-to-b from-amber-100 to-amber-600 tracking-widest text-glow" style={{ fontFamily: '"Ma Shan Zheng", serif' }}>
                    轮回殿堂
                </h2>

                {/* Karma Display */}
                <div className="flex items-center gap-3 px-5 py-1.5 rounded-full bg-amber-950/20 border border-amber-500/30 backdrop-blur-sm mt-4 shadow-[0_0_15px_rgba(245,158,11,0.1)]">
                    <span className="w-2 h-2 rounded-full bg-amber-500 animate-pulse"></span>
                    <span className="text-amber-100 font-bold font-mono tracking-widest text-lg">{metaState.karma}</span>
                    <span className="text-xs text-amber-500/70 tracking-widest">轮回点</span>
                </div>
            </div>

            {/* Update List */}
            <div className="flex-1 w-full max-w-[1200px] px-6 pb-24 overflow-y-auto no-scrollbar z-10 mask-image-b">
                {/* Hint */}
                {metaState.karma === 0 && (
                    <div className="text-center mb-8 text-slate-500 font-serif tracking-widest text-sm bg-slate-900/50 py-2 rounded border border-slate-800/50 mx-auto max-w-md">
                        提示: 在游戏中度过一生，根据评分可获得轮回点。
                    </div>
                )}

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {META_UPGRADES.map(u => {
                        const level = metaState.unlockedUpgrades[u.id] || 0;
                        const cost = getCost(u, level);
                        const canAfford = metaState.karma >= cost;

                        return (
                            <div key={u.id} className="relative group bg-slate-900/40 backdrop-blur-sm border border-slate-700/50 hover:border-amber-500/40 rounded-xl p-6 transition-all duration-300 hover:bg-slate-800/60 hover:-translate-y-1 hover:shadow-[0_0_20px_rgba(245,158,11,0.05)] flex flex-col h-full">
                                <div className="flex justify-between items-start mb-4">
                                    <h3 className="text-xl font-serif font-bold text-amber-100/90 tracking-widest group-hover:text-amber-400 transition-colors">{u.name}</h3>
                                    <div className="px-2 py-0.5 rounded text-xs font-mono text-amber-500/80 bg-amber-950/30 border border-amber-500/20">Lv.{level}</div>
                                </div>

                                <p className="text-sm text-slate-400 mb-6 leading-relaxed font-serif opacity-80 min-h-[3em]">{u.desc}</p>

                                <div className="mt-auto space-y-4">
                                    <div className="text-sm text-slate-300 font-mono flex items-center justify-between bg-black/20 p-2 rounded border border-white/5">
                                        <span className="text-slate-500">当前效果</span>
                                        <div className="flex items-center gap-2">
                                            <span>{u.effectDesc(level)}</span>
                                            <span className="text-slate-600">→</span>
                                            <span className="text-emerald-400 font-bold">{u.effectDesc(level + 1)}</span>
                                        </div>
                                    </div>

                                    <button
                                        onClick={() => purchaseUpgrade(u.id, cost)}
                                        disabled={!canAfford}
                                        className={`w-full py-3 rounded-lg border text-sm tracking-[0.3em] font-serif font-bold transition-all duration-300 relative overflow-hidden group/btn
                                            ${canAfford
                                                ? 'bg-amber-950/40 border-amber-500/40 text-amber-200 hover:bg-amber-900/60 hover:border-amber-400 hover:shadow-[0_0_15px_rgba(245,158,11,0.15)] cursor-pointer'
                                                : 'bg-slate-900/50 border-slate-800 text-slate-600 cursor-not-allowed opacity-50'
                                            }
                                        `}
                                    >
                                        <div className="flex items-center justify-center gap-2 relative z-10">
                                            <span>升级消耗</span>
                                            <span className="font-mono">{cost}</span>
                                        </div>
                                        {canAfford && <div className="absolute inset-0 bg-gradient-to-r from-transparent via-amber-500/10 to-transparent translate-x-[-100%] group-hover/btn:translate-x-[100%] transition-transform duration-500"></div>}
                                    </button>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* Footer / Back Button */}
            <div className="absolute bottom-6 z-20 w-full px-6 flex justify-between items-end pointer-events-none">
                <button
                    onClick={() => useUIStore.getState().setScene('MENU')}
                    className="pointer-events-auto flex items-center gap-2 px-6 py-2 rounded-full bg-slate-900/80 border border-slate-700/50 text-slate-400 hover:text-white hover:border-slate-500 transition-all duration-300 backdrop-blur-md group"
                >
                    <span className="group-hover:-translate-x-1 transition-transform">←</span>
                    <span className="text-sm font-mono tracking-widest">返回主菜单</span>
                </button>

                {/* DEBUG: Free Karma Button (Temporary) */}
                <button
                    onClick={() => useMetaStore.setState(s => ({ metaState: { ...s.metaState, karma: s.metaState.karma + 1000 } }))}
                    className="pointer-events-auto text-[10px] text-slate-700 hover:text-slate-500 transition-colors font-mono"
                >
                    [DEBUG] +1000
                </button>
            </div>
        </div>
    );
};
